// German v2 Unit 15 — Arabic source language (srcLang:"ar")
// تمت الترجمة إلى العربية الفصحى.
const UNIT_15_AR = {n:15,lang:"de",srcLang:"ar",track:"v2",title:"Reise nach Hamburg",sub:"Business trip, genitive case, N-Deklination, regional differences",icon:"🚄",level:"B1.1",color:"#7B5EE8",lessons:[
    {id:"deu_r15l1",title:"Moin, Hamburg!",icon:"🌧️",xp:15,board:true,steps:[
        {type:"intro",title:"Moin, Hamburg!",desc:"يصل فيروميوس إلى هامبورغ في رحلة عمل. مطر وطوب أحمر وتحية لم يسمعها من قبل.",goals:[
            "تعلّم مفردات السفر والجغرافيا",
            "استمع إلى أول تركيب في حالة الإضافة",
            "تعرّف على ثقافة شمال ألمانيا",
            "افهم التحيات الإقليمية"
          ]},
        {type:"story",speaker:"narrator",mood:"descriptive",art:"de-ham-hauptbahnhof",trg:"Hamburg Hauptbahnhof. Regen, roter Backstein, der Geruch der Nordsee in der Luft. Alles hier ist anders als in Berlin.",src:"محطة هامبورغ المركزية. مطر، طوب أحمر، رائحة بحر الشمال في الهواء. كل شيء هنا مختلف عن برلين."},
        {type:"story",speaker:"colleague",mood:"friendly",art:"de-ham-hauptbahnhof",trg:"Moin! Sie müssen Herr Verumius sein. Willkommen in Hamburg!",src:"موين! لا بد أنك السيد فيروميوس. أهلاً بك في هامبورغ!"},
        {type:"story",speaker:"verumius",mood:"happy",art:"de-ham-hauptbahnhof",trg:"Hallo! Danke, dass Sie mich abholen. Was bedeutet 'Moin'?",src:"مرحباً! شكراً لاستقبالي. ماذا تعني كلمة 'Moin'؟"},
        {type:"story",speaker:"colleague",mood:"amused",art:"de-ham-hauptbahnhof",trg:"Moin ist unser Hallo hier im Norden. Morgens, abends, immer: Moin!",src:"موين هي تحيتنا هنا في الشمال. صباحاً، مساءً، دائماً: موين!"},
        {type:"teach",trg:"der Hauptbahnhof",src:"محطة القطار الرئيسية",pos:"noun",gender:"m",note:"Haupt (رئيسي) + Bahnhof (محطة قطار). كل مدينة ألمانية كبيرة لديها واحدة.",example:"A: Entschuldigung, wo ist der Hauptbahnhof?\nB: Geradeaus, dann links.\nA: Wie weit ist es?\nB: Etwa zehn Minuten zu Fuß.",exampleSrc:"A: عفواً، أين محطة القطار الرئيسية؟\nB: مباشرة إلى الأمام، ثم يساراً.\nA: كم تبعد؟\nB: حوالي عشر دقائق سيراً على الأقدام.",funFact:"تستقبل محطة هامبورغ المركزية 550,000 مسافر يومياً، مما يجعلها من أكثر المحطات ازدحاماً في أوروبا. افتُتحت عام 1906 وظلت قلب المدينة منذ ذلك الحين."},
        {type:"teach",trg:"der Hafen",src:"الميناء",pos:"noun",gender:"m",note:"هامبورغ لديها ثالث أكبر ميناء في أوروبا. مرتبطة بالكلمة الإنجليزية 'haven'.",example:"A: Wollen wir zum Hafen gehen?\nB: Ja, gern! Ich liebe den Hamburger Hafen.\nA: Kann man dort Schiffe sehen?\nB: Ja, riesige Containerschiffe!",exampleSrc:"A: هل نذهب إلى الميناء؟\nB: نعم، بكل سرور! أحب ميناء هامبورغ.\nA: هل يمكن رؤية السفن هناك؟\nB: نعم، سفن حاويات ضخمة!",funFact:"شكّل الميناء هوية هامبورغ لأكثر من 800 عام. تُسمى المدينة رسمياً 'مدينة هامبورغ الحرة الهانزية' بسبب تاريخها التجاري."},
        {type:"teach",trg:"die Region",src:"المنطقة",pos:"noun",gender:"f",note:"مستعارة من اللاتينية 'regio'. لدى ألمانيا هويات إقليمية قوية.",example:"A: Aus welcher Region kommen Sie?\nB: Ich komme aus der Region Hamburg.\nA: Das ist eine schöne Region.\nB: Ja, wir haben das Meer und die Stadt.",exampleSrc:"A: من أي منطقة أنت؟\nB: أنا من منطقة هامبورغ.\nA: هذه منطقة جميلة.\nB: نعم، لدينا البحر والمدينة.",funFact:"لدى ألمانيا 16 ولاية اتحادية، لكل منها لهجات وأطعمة وثقافة مميزة. سكان هامبورغ وميونخ قد يبدون وكأنهم من بلدين مختلفين."},
        {type:"teach",trg:"die Gegend",src:"المنطقة المحيطة",pos:"noun",gender:"f",note:"من 'gegen' (ضد/نحو). أقل رسمية من Region.",example:"A: Kennen Sie die Gegend?\nB: Ja, ich wohne in dieser Gegend.\nA: Gibt es hier gute Restaurants?\nB: Ja, viele! Besonders am Hafen.",exampleSrc:"A: هل تعرف المنطقة؟\nB: نعم، أسكن في هذه المنطقة.\nA: هل توجد مطاعم جيدة هنا؟\nB: نعم، كثيرة! خاصة عند الميناء.",funFact:"'In dieser Gegend' (في هذه المنطقة) من أكثر العبارات فائدة للتنقل في مدينة جديدة. أكثر عفوية من 'Region'."},
        {type:"teach",trg:"das Gebiet",src:"الإقليم / المنطقة الرسمية",pos:"noun",gender:"n",note:"أكثر رسمية من Gegend. تُستخدم على اللافتات وفي السياقات الرسمية.",example:"A: Dieses Gebiet ist ein Naturschutzgebiet.\nB: Darf man hier wandern?\nA: Ja, aber bleiben Sie auf den Wegen.\nB: Natürlich!",exampleSrc:"A: هذه المنطقة محمية طبيعية.\nB: هل يمكن التنزه هنا؟\nA: نعم، لكن ابقَ على المسارات.\nB: بالطبع!",funFact:"الكلمات المركبة مع Gebiet شائعة جداً: Wohngebiet (منطقة سكنية)، Industriegebiet (منطقة صناعية)، Stadtgebiet (منطقة حضرية). تراها على اللافتات الرسمية في كل مكان."},
        {type:"teach",trg:"der Nebel",src:"الضباب",pos:"noun",gender:"m",note:"من نفس الجذر اللاتيني 'nebula'. هامبورغ مشهورة بالضباب والمطر.",example:"A: Ich sehe nichts! Alles ist weiß.\nB: Das ist der Nebel. Typisch Hamburg.\nA: Wie lange bleibt der Nebel?\nB: Manchmal den ganzen Tag.",exampleSrc:"A: لا أستطيع رؤية شيء! كل شيء أبيض.\nB: هذا هو الضباب. هامبورغ النموذجية.\nA: كم يبقى الضباب؟\nB: أحياناً طوال اليوم.",funFact:"'Nebel über der Elbe' (ضباب فوق نهر الإلبه) هو شعار هامبورغ عملياً. تشهد المدينة 52 يوماً ضبابياً في المتوسط سنوياً."},
        {type:"teach",trg:"die Richtung",src:"الاتجاه",pos:"noun",gender:"f",note:"من 'richten' (يوجّه). تراها على كل لافتة طريق.",example:"A: In welche Richtung muss ich gehen?\nB: In Richtung Hafen.\nA: Links oder rechts?\nB: Geradeaus, dann rechts.",exampleSrc:"A: في أي اتجاه يجب أن أذهب؟\nB: باتجاه الميناء.\nA: يساراً أم يميناً؟\nB: مباشرة، ثم يميناً.",funFact:"'In Richtung' متبوعة بالوجهة هي طريقة الألمان في إعطاء الاتجاهات على الطرق السريعة واللافتات. 'A7 in Richtung Hamburg' تعني الطريق السريع A7 باتجاه هامبورغ."},
        {type:"teach",trg:"die Strecke",src:"المسار / الطريق",pos:"noun",gender:"f",note:"مسار محدد من نقطة أ إلى ب. شائعة جداً في السفر بالقطار.",example:"A: Die Strecke Hamburg-Berlin ist sehr beliebt.\nB: Wie lange dauert die Fahrt?\nA: Etwa 1 Stunde 45 Minuten mit dem ICE.\nB: Das ist schnell!",exampleSrc:"A: خط هامبورغ-برلين مشهور جداً.\nB: كم تستغرق الرحلة؟\nA: حوالي ساعة و45 دقيقة بقطار ICE.\nB: هذا سريع!",funFact:"كان خط هامبورغ-برلين من أوائل خطوط القطارات فائقة السرعة في ألمانيا. تقطع قطارات ICE مسافة 290 كم في أقل من ساعتين."},
        {type:"teach",trg:"die Verbindung",src:"الاتصال / الرحلة",pos:"noun",gender:"f",note:"Ver- + Bindung (رابطة). على القطارات الألمانية، تعني رحلة القطار المحددة.",example:"A: Gibt es eine direkte Verbindung nach Hamburg?\nB: Ja, der ICE fährt direkt.\nA: Muss ich umsteigen?\nB: Nein, die Verbindung ist direkt.",exampleSrc:"A: هل توجد رحلة مباشرة إلى هامبورغ؟\nB: نعم، قطار ICE يذهب مباشرة.\nA: هل يجب أن أغيّر القطار؟\nB: لا، الرحلة مباشرة.",funFact:"على تطبيق القطارات الألمانية، 'Verbindung suchen' (ابحث عن رحلة) هو أول زر تضغطه. يتحقق الألمان من الرحلات باستمرار عند السفر."},
        {type:"teach",trg:"die Station",src:"المحطة",pos:"noun",gender:"f",note:"من اللاتينية 'statio'. تُستخدم لمحطات المترو والمحطات الصغيرة.",example:"A: Wie viele Stationen sind es bis zum Hafen?\nB: Drei Stationen mit der U-Bahn.\nA: Welche Station muss ich nehmen?\nB: Station Landungsbrücken.",exampleSrc:"A: كم محطة حتى الميناء؟\nB: ثلاث محطات بالمترو.\nA: أي محطة يجب أن آخذ؟\nB: محطة Landungsbrücken.",funFact:"محطة Landungsbrücken في هامبورغ هي البوابة إلى الميناء. من هناك يمكنك ركوب العبّارات عبر نهر الإلبه بتذكرة نقل عادية."},
        {type:"teach",trg:"die Linie",src:"الخط",pos:"noun",gender:"f",note:"من اللاتينية 'linea'. تُستخدم لخطوط النقل.",example:"A: Welche Linie fährt zum Hauptbahnhof?\nB: Nehmen Sie die Linie U3.\nA: Wie oft fährt die Linie?\nB: Alle fünf Minuten.",exampleSrc:"A: أي خط يذهب إلى المحطة الرئيسية؟\nB: خذ الخط U3.\nA: كم مرة يمر الخط؟\nB: كل خمس دقائق.",funFact:"الألمان دقيقون: ليس فقط 'خذ المترو' بل 'خذ الخط 3'. خط U3 في هامبورغ مشهور بقسمه فوق الأرض مع إطلالة على الميناء."},
        {type:"teach",trg:"die Metropole",src:"المدينة الكبرى",pos:"noun",gender:"f",note:"من اليونانية 'metropolis' (المدينة الأم). هامبورغ ثاني أكبر مدينة في ألمانيا.",example:"A: Hamburg ist eine echte Metropole.\nB: Ja, fast zwei Millionen Einwohner.\nA: Größer als München?\nB: Ja, die zweitgrößte Stadt Deutschlands.",exampleSrc:"A: هامبورغ مدينة كبرى حقيقية.\nB: نعم، ما يقارب مليوني نسمة.\nA: أكبر من ميونخ؟\nB: نعم، ثاني أكبر مدينة في ألمانيا.",funFact:"بعدد سكان 1.9 مليون نسمة، هامبورغ ثاني أكبر مدينة ألمانية بعد برلين. لديها جسور أكثر من البندقية وأمستردام ولندن مجتمعة: أكثر من 2,500 جسر."},
        {type:"teach",trg:"die Nordsee",src:"بحر الشمال",pos:"noun",gender:"f",note:"Nord (شمال) + See (بحر). تحده ألمانيا وهولندا والدنمارك والنرويج وبريطانيا.",example:"A: Kann man von Hamburg die Nordsee sehen?\nB: Nicht direkt. Hamburg liegt an der Elbe.\nA: Wie weit ist die Nordsee?\nB: Etwa 100 Kilometer.",exampleSrc:"A: هل يمكن رؤية بحر الشمال من هامبورغ؟\nB: ليس مباشرة. هامبورغ تقع على نهر الإلبه.\nA: كم يبعد بحر الشمال؟\nB: حوالي 100 كيلومتر.",funFact:"تقع هامبورغ على نهر الإلبه، على بعد 100 كم من بحر الشمال. لكن يمكنك شم الملح في الهواء في الأيام العاصفة. شكّل بحر الشمال هوية المدينة التجارية."},
        {type:"teach",trg:"die Ostsee",src:"بحر البلطيق",pos:"noun",gender:"f",note:"Ost (شرق) + See (بحر). يسميه الألمان 'البحر الشرقي' بينما معظم اللغات تسميه 'البلطيق'.",example:"A: Warst du schon an der Ostsee?\nB: Ja, letzten Sommer.\nA: Ist das Wasser kalt?\nB: Kälter als die Nordsee!",exampleSrc:"A: هل زرت بحر البلطيق من قبل؟\nB: نعم، الصيف الماضي.\nA: هل الماء بارد؟\nB: أبرد من بحر الشمال!",funFact:"يسميه الألمان 'Ostsee' (البحر الشرقي) بينما تستخدم الإنجليزية ومعظم اللغات 'البلطيق'. نفس البحر، منظور مختلف. وجهة عطلات مفضلة لسكان شمال ألمانيا."},
        {type:"teach",trg:"die Nacht",src:"الليل",pos:"noun",gender:"f",note:"من نفس الجذر الإنجليزي 'night' واللاتيني 'nox'.",example:"A: Gute Nacht!\nB: Gute Nacht! Schlaf gut.\nA: Bis morgen.\nB: Bis morgen!",exampleSrc:"A: تصبح على خير!\nB: تصبح على خير! نم جيداً.\nA: إلى الغد.\nB: إلى الغد!",funFact:"شارع ريبربان في هامبورغ مشهور بحياته الليلية. يُلقّب هذا الشارع في حي سانت باولي بـ'الميل الأكثر إثماً' منذ الستينيات."},
        {type:"teach",trg:"feucht",src:"رطب / رطوبة",pos:"adj",gender:null,note:"كلمة تصف هامبورغ في جوهرها. ليست 'nass' (مبللة) ولا 'trocken' (جافة)، بل شيء بينهما.",example:"A: Warum ist alles so feucht hier?\nB: Das ist Hamburg! Immer feucht.\nA: Brauche ich einen Regenschirm?\nB: Immer. Jeden Tag.",exampleSrc:"[AR] A: Why is everything so damp here?\nB: That is Hamburg! Always damp.\nA: Do I need an umbrella?\nB: Always. Every day.",funFact:"مرتبطة بالكلمة الإنجليزية damp عبر الجرمانية القديمة. يعني المناخ البحري لهامبورغ هواءً رطباً طوال العام. يتقبّل السكان المحليون ذلك ببساطة."},
        {type:"teach",trg:"nah",src:"قريب",pos:"adj",gender:null,note:"المقارنة: näher (أقرب). أعلى درجات: am nächsten (الأقرب).",example:"A: Ist der Hafen nah?\nB: Ja, sehr nah. Nur zehn Minuten.\nA: Kann man zu Fuß gehen?\nB: Ja, das ist die nächste Straße.",exampleSrc:"[AR] A: Is the harbor near?\nB: Yes, very near. Only ten minutes.\nA: Can you walk there?\nB: Yes, it is the next street.",funFact:"تُستخدم كلا الصيغتين nah وnahe، لكن في سياقات نحوية مختلفة. Der Hafen ist nah (خبري) في مقابل nahe dem Hafen (حرف جر)."},
        {type:"teach",trg:"nahe",src:"قرب (حرف جر / ظرف)",pos:"prep",gender:null,note:"أكثر أدبية قليلاً من nah. تتبع حالة المفعول به غير المباشر: nahe dem Hafen.",example:"A: Das Hotel liegt nahe dem Hauptbahnhof.\nB: Sehr praktisch!\nA: Ja, alles ist nahe.\nB: Perfekt für eine kurze Geschäftsreise.",exampleSrc:"[AR] A: The hotel is near the main train station.\nB: Very practical!\nA: Yes, everything is nearby.\nB: Perfect for a short business trip.",funFact:"بوصفها حرف جر، تتبع nahe حالة الدايتيف: nahe dem Hafen. وبوصفها ظرفاً، تعمل مثل nah. كلا الصيغتين ترجعان إلى الجذر الجرماني القديم ذاته."},
        {type:"mc",q:"Ein Kollege begrüßt Verumius in Hamburg: 'Moin!' Was bedeutet das?",opts:["Danke","Nur Guten Morgen","Hallo","Auf Wiedersehen"],ans:"Hallo",hint:"هذه التحية من شمال ألمانيا تصلح في أي وقت من اليوم، ليس الصباح فقط."},
        {type:"mc",q:"Hamburg liegt an der Elbe, nahe der ...",opts:["Ostsee","Alpen","Nordsee","Donau"],ans:"Nordsee",hint:"تتجه هامبورغ نحو الشمال الغربي، نحو البحر الواقع بين ألمانيا وإنجلترا."},
        {type:"fb",s:"Die {1} Hamburg-Berlin dauert etwa zwei Stunden.",a:["Strecke"],opts:["Strecke","Station","Linie","Richtung"],hint:"أي كلمة تصف مساراً محدداً بين مدينتين؟",sSrc:"[AR] The Hamburg-Berlin route takes about two hours."},
        {type:"story",speaker:"colleague",mood:"matter-of-fact",art:"de-ham-taxi-rain",trg:"So, die Strecke zum Hotel ist nicht weit. Zehn Minuten, wenn der Verkehr mitmacht.",src:"إذاً، الطريق إلى الفندق ليست بعيدة. عشر دقائق إذا سمحت حركة المرور."},
        {type:"story",speaker:"verumius",mood:"curious",art:"de-ham-taxi-rain",trg:"Hamburg ist größer, als ich dachte. Und feuchter.",src:"هامبورغ أكبر مما تصورت. وأكثر رطوبة."}
      ]},
    {id:"deu_r15l2",title:"Unterwegs in der Stadt",icon:"🚋",xp:15,board:true,steps:[
        {type:"intro",title:"Unterwegs in der Stadt",desc:"تعلّم مفردات النقل الحضري. افهم مصطلحات الطريق والمرور. تنقّل في مدينة ألمانية كالسكان الأصليين.",goals:[
            "تعلّم 20 كلمة في مفردات النقل والمدينة",
            "افهم قواعد تحديد جنس الأسماء المركبة",
            "تنقّل في شوارع هامبورغ ووسائل مواصلاتها"
          ]},
        {type:"teach",trg:"die U-Bahn",src:"[AR] the subway",pos:"noun",gender:"f",note:"[AR] Untergrund (underground) + Bahn (railway). The yellow U sign is iconic.",example:"A: Wie komme ich zum Hafen?\nB: Nehmen Sie die U-Bahn.\nA: Welche Linie?\nB: Die U3 bis Landungsbrücken.",exampleSrc:"[AR] A: How do I get to the harbor?\nB: Take the subway.\nA: Which line?\nB: The U3 to Landungsbrücken.",funFact:"[AR] Hamburg's U-Bahn opened in 1912. Berlin, Munich, Hamburg, and Nuremberg all have U-Bahn systems. The yellow U sign marks every entrance."},
        {type:"teach",trg:"die Tram",src:"[AR] the streetcar / tram",pos:"noun",gender:"f",note:"[AR] Short for 'Trambahn.' Most German cities have tram networks.",example:"A: Fährt hier eine Tram?\nB: Nein, Hamburg hat keine Tram mehr.\nA: Wirklich? Warum nicht?\nB: Die Stadt hat sie 1978 abgeschafft.",exampleSrc:"[AR] A: Does a tram run here?\nB: No, Hamburg no longer has a tram.\nA: Really? Why not?\nB: The city removed them in 1978.",funFact:"[AR] Hamburg actually removed its trams in 1978, but most German cities kept theirs. Berlin has one of Europe's largest tram networks with over 190 km of track."},
        {type:"teach",trg:"die Fähre",src:"[AR] the ferry",pos:"noun",gender:"f",note:"[AR] From 'fahren' (to travel). Hamburg's harbor ferries are part of public transport.",example:"A: Kann man mit der Fähre fahren?\nB: Ja! Die Fähre gehört zum HVV.\nA: Brauche ich ein extra Ticket?\nB: Nein, Ihr normales Ticket reicht.",exampleSrc:"[AR] A: Can you take the ferry?\nB: Yes! The ferry is part of the HVV.\nA: Do I need an extra ticket?\nB: No, your normal ticket is enough.",funFact:"[AR] Hamburg's harbor ferries are part of the public transport system (HVV). You can ride them with a normal transit ticket, making them the cheapest harbor tour in the city."},
        {type:"teach",trg:"die Eisenbahn",src:"[AR] the railway",pos:"noun",gender:"f",note:"[AR] Eisen (iron) + Bahn (track). Literally 'iron track.'",example:"A: Die Eisenbahn ist in Deutschland sehr wichtig.\nB: Ja, viele Menschen fahren mit der Bahn.\nA: Seit wann gibt es die Eisenbahn?\nB: Seit 1835 in Deutschland.",exampleSrc:"[AR] A: The railway is very important in Germany.\nB: Yes, many people travel by train.\nA: Since when has the railway existed?\nB: Since 1835 in Germany.",funFact:"[AR] The first German Eisenbahn ran in 1835 between Nürnberg and Fürth, just 6 km. Today Germany has over 33,000 km of track."},
        {type:"teach",trg:"das Fahrzeug",src:"[AR] the vehicle",pos:"noun",gender:"n",note:"[AR] Fahr (drive) + Zeug (stuff/thing). Literally 'driving-thing.'",example:"A: Was für ein Fahrzeug haben Sie?\nB: Ich habe ein kleines Auto.\nA: In Hamburg braucht man kein Fahrzeug.\nB: Stimmt, die U-Bahn reicht.",exampleSrc:"[AR] A: What kind of vehicle do you have?\nB: I have a small car.\nA: In Hamburg you do not need a vehicle.\nB: True, the subway is enough.",funFact:"[AR] The Zeug pattern is productive: Fahrzeug (vehicle), Flugzeug (airplane = flying-thing), Werkzeug (tool = work-thing), Spielzeug (toy = play-thing). Gender always comes from the last element."},
        {type:"teach",trg:"das Motorrad",src:"[AR] the motorcycle",pos:"noun",gender:"n",note:"[AR] Motor + Rad (wheel). Germany is the birthplace of the motorcycle.",example:"A: Fährst du Motorrad?\nB: Ja, im Sommer. Im Winter ist es zu kalt.\nA: Ist es gefährlich?\nB: Nur wenn man nicht aufpasst.",exampleSrc:"[AR] A: Do you ride a motorcycle?\nB: Yes, in summer. In winter it is too cold.\nA: Is it dangerous?\nB: Only if you do not pay attention.",funFact:"[AR] Gottlieb Daimler built the first motorcycle in 1885 in Bad Cannstatt, Germany. Today Germany has over 4 million registered motorcycles."},
        {type:"teach",trg:"das Kraftfahrzeug",src:"[AR] the motor vehicle",pos:"noun",gender:"n",note:"[AR] Kraft (power) + Fahrzeug (vehicle). Abbreviated KFZ. On every vehicle registration.",example:"A: Was ist ein Kraftfahrzeug?\nB: Jedes Fahrzeug mit Motor.\nA: Also Auto, Motorrad, LKW?\nB: Genau. Alles mit Motor ist ein KFZ.",exampleSrc:"[AR] A: What is a Kraftfahrzeug?\nB: Any vehicle with an engine.\nA: So car, motorcycle, truck?\nB: Exactly. Everything with an engine is a KFZ.",funFact:"[AR] KFZ is one of Germany's most common abbreviations. 'KFZ-Versicherung' (vehicle insurance) and 'KFZ-Zulassungsstelle' (vehicle registration office) are words every German driver knows."},
        {type:"teach",trg:"die Fahrbahn",src:"[AR] the roadway / carriageway",pos:"noun",gender:"f",note:"[AR] Fahr (drive) + Bahn (track). The actual surface where vehicles drive.",example:"A: Bleiben Sie auf der Fahrbahn!\nB: Ich bin Radfahrer. Wo soll ich fahren?\nA: Auf dem Radweg, nicht auf der Fahrbahn.\nB: Oh, Entschuldigung!",exampleSrc:"[AR] A: Stay on the roadway!\nB: I am a cyclist. Where should I ride?\nA: On the bike path, not on the roadway.\nB: Oh, sorry!",funFact:"[AR] In Germany, the Fahrbahn is strictly for motor vehicles. Cyclists use the Radweg (bike path) and pedestrians use the Gehsteig (sidewalk). Mixing them up is frowned upon."},
        {type:"teach",trg:"die Einbahnstraße",src:"[AR] the one-way street",pos:"noun",gender:"f",note:"[AR] Ein (one) + Bahn (track) + Straße (street). Common in old town centers.",example:"A: Kann ich hier rechts fahren?\nB: Nein, das ist eine Einbahnstraße!\nA: In welche Richtung?\nB: Nur nach links.",exampleSrc:"[AR] A: Can I turn right here?\nB: No, that is a one-way street!\nA: In which direction?\nB: Only to the left.",funFact:"[AR] German old town centers are full of Einbahnstraßen. The blue sign with a white arrow marks them. Tourists often learn this word the hard way."},
        {type:"teach",trg:"die Einfahrt",src:"[AR] the entry / entrance (for vehicles)",pos:"noun",gender:"f",note:"[AR] Ein (in) + Fahrt (drive). On garage doors: 'Einfahrt freihalten!'",example:"A: Wo ist die Einfahrt zum Parkhaus?\nB: Die nächste Straße rechts.\nA: Ist die Einfahrt breit genug?\nB: Ja, kein Problem.",exampleSrc:"[AR] A: Where is the entrance to the parking garage?\nB: The next street on the right.\nA: Is the entrance wide enough?\nB: Yes, no problem.",funFact:"[AR] 'Einfahrt freihalten!' (Keep entrance clear!) is one of the most common signs on German garage doors. Germans take this very seriously."},
        {type:"teach",trg:"die Ausfahrt",src:"[AR] the exit (for vehicles)",pos:"noun",gender:"f",note:"[AR] Aus (out) + Fahrt (drive). On the Autobahn, every exit has a number.",example:"A: Welche Ausfahrt müssen wir nehmen?\nB: Ausfahrt 23: Hamburg-Harburg.\nA: Wie weit ist das noch?\nB: Noch zehn Kilometer.",exampleSrc:"[AR] A: Which exit do we need to take?\nB: Exit 23: Hamburg-Harburg.\nA: How far is that?\nB: Ten more kilometers.",funFact:"[AR] Every tourist giggles at how often they see 'Ausfahrt' on the Autobahn. It just means 'exit,' but it sounds exotic when you cannot read German yet."},
        {type:"teach",trg:"der Fußgänger",src:"[AR] the pedestrian (male)",pos:"noun",gender:"m",note:"[AR] Fuß (foot) + Gänger (goer). Germany has strict pedestrian rules.",example:"A: Hier dürfen nur Fußgänger gehen.\nB: Keine Autos?\nA: Nein, das ist eine Fußgängerzone.\nB: Sehr angenehm!",exampleSrc:"[AR] A: Only pedestrians may walk here.\nB: No cars?\nA: No, this is a pedestrian zone.\nB: Very pleasant!",funFact:"[AR] Jaywalking is frowned upon in Germany. Crossing on red earns you disapproving looks, especially from parents with children. In Switzerland, the sidewalk is called 'Trottoir' (from French)."},
        {type:"teach",trg:"die Fußgängerin",src:"[AR] the pedestrian (female)",pos:"noun",gender:"f",note:"[AR] Feminine form of Fußgänger. The -in suffix for feminine persons.",example:"A: Die Fußgängerin wartet an der Ampel.\nB: Sehr vorbildlich!\nA: In Hamburg warten alle bei Rot.\nB: Das ist typisch norddeutsch.",exampleSrc:"[AR] A: The pedestrian is waiting at the traffic light.\nB: Very exemplary!\nA: In Hamburg everyone waits at red.\nB: That is typically northern German.",funFact:"[AR] The -in suffix for feminine persons is consistent: Lehrer/Lehrerin, Fahrer/Fahrerin, Fußgänger/Fußgängerin. It is one of German's most productive patterns."},
        {type:"teach",trg:"die Fußgängerzone",src:"[AR] the pedestrian zone",pos:"noun",gender:"f",note:"[AR] Fußgänger + Zone. No cars, only people, shops, and cafes.",example:"A: Gibt es in Hamburg eine Fußgängerzone?\nB: Ja, die Mönckebergstraße.\nA: Kann man dort einkaufen?\nB: Ja, viele Geschäfte und Kaufhäuser.",exampleSrc:"[AR] A: Is there a pedestrian zone in Hamburg?\nB: Yes, Mönckebergstraße.\nA: Can you shop there?\nB: Yes, many shops and department stores.",funFact:"[AR] Every German city center has a Fußgängerzone. Hamburg's Mönckebergstraße is one of the city's main shopping streets."},
        {type:"teach",trg:"der Radfahrer",src:"[AR] the cyclist (male)",pos:"noun",gender:"m",note:"[AR] Rad (wheel/bicycle) + Fahrer (driver). Germany has excellent cycling infrastructure.",example:"A: Vorsicht, ein Radfahrer!\nB: Wo? Ich sehe ihn nicht.\nA: Auf dem Radweg links.\nB: Oh ja, danke!",exampleSrc:"[AR] A: Watch out, a cyclist!\nB: Where? I do not see him.\nA: On the bike path to the left.\nB: Oh yes, thanks!",funFact:"[AR] Germany has excellent cycling infrastructure. In Switzerland, a bicycle is called 'Velo' (from French vélocipède), not 'Fahrrad.'"},
        {type:"teach",trg:"die Radfahrerin",src:"[AR] the cyclist (female)",pos:"noun",gender:"f",note:"[AR] Feminine cyclist. Same -in pattern.",example:"A: Die Radfahrerin fährt sehr schnell.\nB: Ja, in Hamburg sind viele Radfahrerinnen unterwegs.\nA: Gibt es gute Radwege?\nB: Ja, die Stadt investiert viel in Radwege.",exampleSrc:"[AR] A: The cyclist is riding very fast.\nB: Yes, many cyclists are out and about in Hamburg.\nA: Are there good bike paths?\nB: Yes, the city invests a lot in bike paths.",funFact:"[AR] Hamburg is investing heavily in cycling infrastructure with the 'Velorouten' network, connecting the city's neighborhoods with dedicated bike highways."},
        {type:"teach",trg:"die Zone",src:"[AR] the zone",pos:"noun",gender:"f",note:"[AR] From Greek 'zone' (belt/girdle). Very versatile word in German.",example:"A: Wir fahren in Zone A.\nB: Brauchen wir ein anderes Ticket für Zone B?\nA: Ja, ein Erweiterungsticket.\nB: Das ist kompliziert!",exampleSrc:"[AR] A: We are traveling in Zone A.\nB: Do we need a different ticket for Zone B?\nA: Yes, an extension ticket.\nB: That is complicated!",funFact:"[AR] 'Umweltzone' (low-emission zone) covers most German city centers. Only vehicles with a green sticker may enter. 'Zeitzone' = time zone. A versatile word."},
        {type:"teach",trg:"die Spur",src:"[AR] the lane / track / trace",pos:"noun",gender:"f",note:"[AR] Also means 'trace' or 'clue' in detective stories.",example:"A: Bleiben Sie auf der rechten Spur.\nB: Warum?\nA: Die linke Spur ist nur zum Überholen.\nB: Ah, wie auf der Autobahn.",exampleSrc:"[AR] A: Stay in the right lane.\nB: Why?\nA: The left lane is only for passing.\nB: Ah, like on the Autobahn.",funFact:"[AR] On the Autobahn, 'die rechte Spur' (right lane) is for normal driving, 'die linke Spur' (left lane) is for overtaking only. Germans take this rule very seriously."},
        {type:"teach",trg:"die Kurve",src:"[AR] the curve / bend",pos:"noun",gender:"f",note:"[AR] Related to English 'curve' via Latin 'curvus.'",example:"A: Vorsicht, scharfe Kurve!\nB: Ich fahre langsam.\nA: Diese Kurven sind gefährlich bei Regen.\nB: Ja, die Straße ist glatt.",exampleSrc:"[AR] A: Caution, sharp curve!\nB: I am driving slowly.\nA: These curves are dangerous in the rain.\nB: Yes, the road is slippery.",funFact:"[AR] On mountain roads, you see 'Vorsicht, scharfe Kurve!' (Caution, sharp curve!) constantly. The word also works figuratively: 'die Kurve kriegen' = to get it together."},
        {type:"teach",trg:"die Lage",src:"[AR] the location / situation",pos:"noun",gender:"f",note:"[AR] Context determines meaning: 'location' or 'situation.'",example:"A: Die Lage des Hotels ist perfekt.\nB: Ja, direkt am Hafen.\nA: Und die politische Lage?\nB: Das ist eine andere Frage!",exampleSrc:"[AR] A: The location of the hotel is perfect.\nB: Yes, right on the harbor.\nA: And the political situation?\nB: That is a different question!",funFact:"[AR] 'Die Lage des Hotels' (the location of the hotel) sneaks in a genitive construction. You will learn this case formally in the next lesson."},
        {type:"mc",q:"Kraftfahrzeug is made of Kraft + Fahrzeug. What does Kraft mean?",opts:["New","Power","Big","Fast"],ans:"Power",hint:"[AR] KFZ is a ___-vehicle. What does that first element contribute?"},
        {type:"fb",s:"In der Hamburger Innenstadt gibt es eine große {1}.",a:["Fußgängerzone"],opts:["Fußgängerzone","Einbahnstraße","Ausfahrt","Fahrbahn"],hint:"[AR] A zone where only pedestrians walk, no cars allowed.",sSrc:"[AR] In Hamburg's city center there is a large pedestrian zone."},
        {type:"match",pairs:[
            {trg:"U-Bahn",src:"subway"},
            {trg:"Fähre",src:"ferry"},
            {trg:"Eisenbahn",src:"railway"},
            {trg:"Motorrad",src:"motorcycle"},
            {trg:"Tram",src:"streetcar"}
          ]},
        {type:"mc",q:"Welcher Artikel ist richtig: ___ Kraftfahrzeug?",opts:["die","der","ein","das"],ans:"das",hint:"[AR] In compound nouns, the LAST element determines the article. Fahrzeug is neuter."},
        {type:"drag_fill",s:"Nehmen Sie die nächste {1} auf der rechten {2}.",blanks:{"1":"Ausfahrt","2":"Spur"},pool:["Ausfahrt","Spur","Einfahrt","Kurve","Linie","Zone"],hint:"[AR] Take the next exit on the right lane. Two road/highway terms.",sSrc:"[AR] Take the next exit on the right lane."}
      ]},
    {id:"deu_r15l3",title:"Herr Professor Doktor Schmidt",icon:"👔",xp:15,board:true,steps:[
        {type:"intro",title:"Herr Professor Doktor Schmidt",desc:"[AR] Navigate a formal German meeting. Learn the genitive case: 'des Mannes, der Frau.' Understand German title culture.",goals:[
            "[AR] Master building and location vocabulary",
            "[AR] Learn the genitive case",
            "[AR] Navigate professional introductions",
            "[AR] Understand German title culture"
          ]},
        {type:"story",speaker:"narrator",mood:"formal",art:"de-ham-office",trg:"Das Büro des Unternehmens liegt direkt am Hafen. Durch die Fenster sieht Verumius die Kräne der Hafenstadt.",src:"[AR] The company's office is right on the harbor. Through the windows, Verumius sees the cranes of the harbor city."},
        {type:"story",speaker:"colleague",mood:"formal",art:"de-ham-office",trg:"Darf ich vorstellen? Das ist Herr Professor Doktor Schmidt, der Leiter der Abteilung.",src:"[AR] May I introduce? This is Herr Professor Doktor Schmidt, the head of the department."},
        {type:"story",speaker:"verumius",mood:"nervous",art:"de-ham-office",trg:"Guten Tag, Herr Professor Doktor Schmidt. Es ist mir eine Ehre.",src:"[AR] Good day, Herr Professor Doktor Schmidt. It is an honor."},
        {type:"story",speaker:"colleague",mood:"amused",art:"de-ham-office",trg:"In Hamburg sagen wir alle Titel. Der Name des Kollegen ist wichtig, aber die Titel sind heilig!",src:"[AR] In Hamburg we say all titles. The colleague's name is important, but the titles are sacred!"},
        {type:"teach",trg:"das Gebäude",src:"[AR] the building",pos:"noun",gender:"n",note:"[AR] From 'bauen' (to build). The Ge- prefix creates a collective noun.",example:"A: Was für ein Gebäude ist das?\nB: Das ist die Elbphilharmonie.\nA: Ein beeindruckendes Gebäude!\nB: Ja, das berühmteste Gebäude Hamburgs.",exampleSrc:"[AR] A: What kind of building is that?\nB: That is the Elbphilharmonie.\nA: An impressive building!\nB: Yes, Hamburg's most famous building.",funFact:"[AR] The Ge- prefix creates collective nouns: Gebäude (building), Gepäck (luggage), Gebirge (mountain range). The Elbphilharmonie is Hamburg's most famous Gebäude."},
        {type:"teach",trg:"der Turm",src:"[AR] the tower",pos:"noun",gender:"m",note:"[AR] From Latin 'turris.' Hamburg's Michel (St. Michaelis) is the city's landmark.",example:"A: Sehen Sie den Turm dort?\nB: Ja, das ist der Michel.\nA: Wie hoch ist er?\nB: 132 Meter. Man kann hinaufsteigen.",exampleSrc:"[AR] A: Do you see the tower there?\nB: Yes, that is the Michel.\nA: How tall is it?\nB: 132 meters. You can climb up.",funFact:"[AR] Hamburg's Michel (St. Michaelis church tower) is the city's landmark. Berlin's Fernsehturm (TV tower) is 368 m tall. The word Turm is related to English 'tower.'"},
        {type:"teach",trg:"der Hof",src:"[AR] the courtyard / yard / farm",pos:"noun",gender:"m",note:"[AR] One of German's most productive compound elements.",example:"A: Der Hof des Gebäudes ist wunderschön.\nB: Ja, mit Bäumen und einer Bank.\nA: Haben alle Gebäude einen Hof?\nB: Viele Altbauten, ja.",exampleSrc:"[AR] A: The courtyard of the building is beautiful.\nB: Yes, with trees and a bench.\nA: Do all buildings have a courtyard?\nB: Many old buildings, yes.",funFact:"[AR] 'Hof' appears in many compounds: Bahnhof (train yard), Bauernhof (farm), Innenhof (inner courtyard), Friedhof (peace-yard = cemetery). One root, endless compounds."},
        {type:"teach",trg:"der Vorort",src:"[AR] the suburb",pos:"noun",gender:"m",note:"[AR] Vor (before/in front of) + Ort (place). Literally 'fore-place.'",example:"A: Wohnen Sie in Hamburg?\nB: Nein, in einem Vorort.\nA: Ist es weit zur Arbeit?\nB: Nein, nur 20 Minuten mit der S-Bahn.",exampleSrc:"[AR] A: Do you live in Hamburg?\nB: No, in a suburb.\nA: Is it far to work?\nB: No, only 20 minutes by commuter rail.",funFact:"[AR] Hamburg's Vororte stretch far along the Elbe. German suburbs feel different from American ones: denser, with better public transport and local bakeries."},
        {type:"teach",trg:"das Ufer",src:"[AR] the bank / shore (of a river)",pos:"noun",gender:"n",note:"[AR] Related to English 'over' via Proto-Germanic.",example:"A: Gehen wir am Ufer der Elbe spazieren?\nB: Gute Idee! Das Ufer ist hier sehr schön.\nA: Kann man dort sitzen?\nB: Ja, es gibt Bänke am Ufer.",exampleSrc:"[AR] A: Shall we walk along the bank of the Elbe?\nB: Good idea! The shore is very beautiful here.\nA: Can you sit there?\nB: Yes, there are benches on the bank.",funFact:"[AR] Hamburg's HafenCity neighborhood sits on the Ufer der Elbe. 'Am Ufer' (on the bank) is one of the most scenic phrases in Hamburg's vocabulary."},
        {type:"teach",trg:"die Küste",src:"[AR] the coast",pos:"noun",gender:"f",note:"[AR] From Latin 'costa' (rib/side). Famous for Wattwanderung (mudflat hiking).",example:"A: Waren Sie schon an der Küste?\nB: Ja, an der Nordseeküste.\nA: Wie ist es dort?\nB: Windig und wunderschön!",exampleSrc:"[AR] A: Have you been to the coast?\nB: Yes, to the North Sea coast.\nA: What is it like there?\nB: Windy and beautiful!",funFact:"[AR] The German North Sea coast is famous for Wattwanderung (mudflat hiking). At low tide, you can walk kilometers into the sea. UNESCO World Heritage since 2009."},
        {type:"teach",trg:"der Ozean",src:"[AR] the ocean",pos:"noun",gender:"m",note:"[AR] From Greek 'Okeanos.' Hamburg's connection to the Atlantic made it great.",example:"A: Der Atlantische Ozean ist nicht weit von Hamburg.\nB: Naja, die Nordsee ist näher.\nA: Die Nordsee ist Teil des Ozeans.\nB: Stimmt!",exampleSrc:"[AR] A: The Atlantic Ocean is not far from Hamburg.\nB: Well, the North Sea is closer.\nA: The North Sea is part of the ocean.\nB: True!",funFact:"[AR] Hamburg's connection to the Atlantic via the Elbe made it one of Europe's greatest trading cities. The word 'Übersee' (overseas) is deeply woven into Hamburg's identity."},
        {type:"teach",trg:"die Distanz",src:"[AR] the distance (formal)",pos:"noun",gender:"f",note:"[AR] From Latin 'distantia.' More formal than 'Entfernung.'",example:"A: Die Distanz zwischen Hamburg und Berlin beträgt 290 km.\nB: Das ist nicht weit.\nA: Mit dem ICE nur 1:45.\nB: Sehr praktisch.",exampleSrc:"[AR] A: The distance between Hamburg and Berlin is 290 km.\nB: That is not far.\nA: By ICE only 1:45.\nB: Very practical.",funFact:"[AR] Distanz is used in professional and scientific contexts. For everyday speech, Germans prefer Entfernung."},
        {type:"teach",trg:"die Entfernung",src:"[AR] the distance (everyday)",pos:"noun",gender:"f",note:"[AR] From 'entfernen' (to remove/move away). More everyday than Distanz.",example:"A: Wie groß ist die Entfernung zum Hafen?\nB: Etwa zwei Kilometer.\nA: Kann man zu Fuß gehen?\nB: Ja, ein schöner Spaziergang.",exampleSrc:"[AR] A: What is the distance to the harbor?\nB: About two kilometers.\nA: Can you walk?\nB: Yes, a nice walk.",funFact:"[AR] Entfernung comes from ent- (away) + fernen (from fern = far). 'In kurzer Entfernung' = at a short distance. More common in daily speech than Distanz."},
        {type:"teach",trg:"städtisch",src:"[AR] urban / municipal",pos:"adj",gender:null,note:"[AR] From 'Stadt' (city). The adjective form of Stadt.",example:"A: Gibt es städtische Busse?\nB: Ja, der städtische Nahverkehr ist gut.\nA: Wie heißt das Unternehmen?\nB: HVV, der Hamburger Verkehrsverbund.",exampleSrc:"[AR] A: Are there municipal buses?\nB: Yes, the municipal public transport is good.\nA: What is the company called?\nB: HVV, the Hamburg Transport Association.",funFact:"[AR] Hamburg's städtische character differs sharply from rural Schleswig-Holstein just north of the city. The urban-rural contrast is one of Germany's defining features."},
        {type:"teach",trg:"regional",src:"[AR] regional",pos:"adj",gender:null,note:"[AR] Same as English. Pronounced 'ray-gee-oh-NAHL.'",example:"A: Gibt es regionale Unterschiede?\nB: Ja, viele! Sprache, Essen, Kultur.\nA: Zum Beispiel?\nB: In Hamburg sagt man 'Moin', in Bayern 'Grüß Gott.'",exampleSrc:"[AR] A: Are there regional differences?\nB: Yes, many! Language, food, culture.\nA: For example?\nB: In Hamburg they say 'Moin', in Bavaria 'Grüß Gott.'",funFact:"[AR] Germany's regional diversity is one of its defining features. From greetings to bread rolls to humor: every Region has its own flavor."},
        {type:"teach",trg:"der Passagier",src:"[AR] the passenger (male)",pos:"noun",gender:"m",note:"[AR] From French 'passager.' Used for ship, plane, and train passengers.",example:"A: Wie viele Passagiere hat das Schiff?\nB: Über 3.000 Passagiere.\nA: Das ist ein riesiges Schiff!\nB: Ja, ein Kreuzfahrtschiff.",exampleSrc:"[AR] A: How many passengers does the ship have?\nB: Over 3,000 passengers.\nA: That is an enormous ship!\nB: Yes, a cruise ship.",funFact:"[AR] In Switzerland, the train platform is called 'Perron' (from French), not 'Bahnsteig.' Swiss German has many French loanwords."},
        {type:"teach",trg:"die Passagierin",src:"[AR] the passenger (female)",pos:"noun",gender:"f",note:"[AR] Feminine form. The -in suffix applies to all person-nouns.",example:"A: Die Passagierin hat ihr Gepäck vergessen.\nB: Im Zug?\nA: Ja, im Speisewagen.\nB: Sie sollte das Fundbüro anrufen.",exampleSrc:"[AR] A: The passenger forgot her luggage.\nB: On the train?\nA: Yes, in the dining car.\nB: She should call the lost and found.",funFact:"[AR] The Passagier/Passagierin pair follows the same -in pattern as Fahrer/Fahrerin. Consistent and productive."},
        {type:"teach",trg:"der Steward",src:"[AR] the steward (male)",pos:"noun",gender:"m",note:"[AR] Borrowed from English. Used for male flight attendants and ship stewards.",example:"A: Der Steward bringt das Essen.\nB: Auf dem Schiff?\nA: Ja, auf dem Kreuzfahrtschiff.\nB: Wie nett!",exampleSrc:"[AR] A: The steward is bringing the food.\nB: On the ship?\nA: Yes, on the cruise ship.\nB: How nice!",funFact:"[AR] Borrowed from English but pronounced with a German R. Used on ships and planes. Increasingly replaced by gender-neutral alternatives in modern German."},
        {type:"teach",trg:"die Stewardess",src:"[AR] the stewardess / flight attendant (female)",pos:"noun",gender:"f",note:"[AR] From English. Increasingly replaced by 'Flugbegleiterin.'",example:"A: Die Stewardess erklärt die Sicherheitsregeln.\nB: Wie sagt man das modern?\nA: Flugbegleiterin.\nB: Das klingt professioneller.",exampleSrc:"[AR] A: The stewardess is explaining the safety rules.\nB: What is the modern term?\nA: Flugbegleiterin (flight companion).\nB: That sounds more professional.",funFact:"[AR] 'Flugbegleiterin' (flight companion, feminine) is the modern replacement for Stewardess. The shift reflects German's ongoing effort to modernize gendered job titles."},
        {type:"teach",trg:"der Laster",src:"[AR] the truck",pos:"noun",gender:"m",note:"[AR] Short for 'Lastkraftwagen' (LKW). Everyday word for truck.",example:"A: Ein großer Laster blockiert die Straße.\nB: Das passiert oft in Hamburg.\nA: Wegen des Hafens?\nB: Ja, viele Laster fahren zum Hafen.",exampleSrc:"[AR] A: A large truck is blocking the street.\nB: That happens often in Hamburg.\nA: Because of the harbor?\nB: Yes, many trucks drive to the harbor.",funFact:"[AR] The formal term is LKW (Lastkraftwagen), but everyone says Laster in everyday speech. On the Autobahn, Laster have a speed limit of 80 km/h."},
        {type:"teach",trg:"der Transport",src:"[AR] the transport",pos:"noun",gender:"m",note:"[AR] From Latin 'transportare.' Hamburg handles 130 million tons of cargo annually.",example:"A: Der Transport der Waren dauert drei Tage.\nB: Von wo?\nA: Vom Hamburger Hafen nach Berlin.\nB: Das ist schnell.",exampleSrc:"[AR] A: The transport of the goods takes three days.\nB: From where?\nA: From Hamburg's harbor to Berlin.\nB: That is fast.",funFact:"[AR] Hamburg's port handles 130 million tons of cargo annually. 'Öffentlicher Nahverkehr' (public transit) is more common than 'öffentlicher Transport' in everyday German."},
        {type:"teach",trg:"transportieren",src:"[AR] to transport",pos:"verb",gender:null,note:"[AR] Regular verb with the -ieren ending from French/Latin.",example:"A: Die Schiffe transportieren Waren aus aller Welt.\nB: Was für Waren?\nA: Alles: Autos, Elektronik, Lebensmittel.\nB: Der Hamburger Hafen ist riesig.",exampleSrc:"[AR] A: The ships transport goods from around the world.\nB: What kind of goods?\nA: Everything: cars, electronics, food.\nB: Hamburg's harbor is enormous.",funFact:"[AR] Verbs ending in -ieren (transportieren, organisieren, telefonieren) are always regular and never get ge- in the past participle: transportiert, not getransportiert."},
        {type:"teach",trg:"dicht",src:"[AR] dense / thick / tight",pos:"adj",gender:null,note:"[AR] 'Dichter Nebel' = thick fog. Also slang for 'drunk' (informal).",example:"A: Der Nebel ist heute sehr dicht.\nB: Ja, man kann kaum etwas sehen.\nA: Typisch Hamburg!\nB: Dichter Nebel, feuchte Luft.",exampleSrc:"[AR] A: The fog is very thick today.\nB: Yes, you can barely see anything.\nA: Typical Hamburg!\nB: Thick fog, damp air.",funFact:"[AR] 'Dicht besiedelt' (densely populated) describes Hamburg's inner city. The word also means 'tight' (a container is dicht) and, in slang, 'drunk.'"},
        {type:"teach",trg:"der Tourismus",src:"[AR] the tourism",pos:"noun",gender:"m",note:"[AR] From French/English. The -ismus suffix marks abstract concepts, always masculine.",example:"A: Der Tourismus ist wichtig für Hamburg.\nB: Wie viele Touristen kommen pro Jahr?\nA: Über 15 Millionen Übernachtungen.\nB: Beeindruckend!",exampleSrc:"[AR] A: Tourism is important for Hamburg.\nB: How many tourists come per year?\nA: Over 15 million overnight stays.\nB: Impressive!",funFact:"[AR] The -ismus suffix is always masculine: Tourismus, Kapitalismus, Optimismus. It marks abstract concepts borrowed through Latin/French/English."},
        {type:"tip",title:"The genitive case: showing possession",text:"[AR] In English, you say 'the man's book' or 'the book of the man.' German uses the genitive case.\n\nMasculine/neuter: change the article to 'des' and add -(e)s to the noun.\nFeminine/plural: change the article to 'der,' noun stays the same.\n\nMaskulin: der Mann becomes des Mannes (of the man)\nFeminin: die Frau becomes der Frau (of the woman)\nNeutral: das Kind becomes des Kindes (of the child)\nPlural: die Kinder becomes der Kinder (of the children)\n\nExamples from the story:\n'der Leiter der Abteilung' = the head of the department\n'der Name des Kollegen' = the colleague's name\n'die Atmosphäre des Hafens' = the atmosphere of the harbor",deepDive:{title:"Genitive in everyday speech",text:"[AR] In casual speech, many Germans avoid genitive and use 'von + dative' instead:\n'das Buch von dem Mann' instead of 'das Buch des Mannes.'\nBut in writing, professional contexts, and with prepositions like 'während,' genitive is essential. Northern Germany (Hamburg!) uses genitive more than southern Germany.\n\nOne-syllable nouns get -es: des Mannes, des Kindes.\nMulti-syllable nouns get just -s: des Hafens, des Gebäudes."}},
        {type:"verb_table",title:"Der Genitiv: Artikel und Endungen",groups:[
            {label:"Bestimmter Artikel (definite)",rows:[
                {pronoun:"maskulin",form:"des Mannes",src:"of the man"},
                {pronoun:"feminin",form:"der Frau",src:"of the woman"},
                {pronoun:"neutral",form:"des Kindes",src:"of the child"},
                {pronoun:"Plural",form:"der Kinder",src:"of the children"}
              ]},
            {label:"Unbestimmter Artikel (indefinite)",rows:[
                {pronoun:"maskulin",form:"eines Mannes",src:"of a man"},
                {pronoun:"feminin",form:"einer Frau",src:"of a woman"},
                {pronoun:"neutral",form:"eines Kindes",src:"of a child"}
              ]}
          ],note:"[AR] Masculine and neuter: des/eines + noun + -(e)s. Feminine and plural: der + noun unchanged.",deepDive:{title:"Proper names in the genitive: Peters Auto",text:"[AR] Two ways to express possession:\n\n1. Name + s: Peters Auto = Peter's car. NO apostrophe!\n2. Article genitive: das Auto des Mannes.\n\nNever mix: Des Peters Auto (wrong). Peters Auto (right).\n\nThe 'Deppenapostroph' (idiot apostrophe): Peter's Auto is grammatically wrong.\nGerman genitive-s comes WITHOUT an apostrophe.\n\nException: names ending in -s, -x, -z use an apostrophe:\nMax' Auto, Hans' Buch (or: das Auto von Max)\n\nThis also applies to place names: Berlins Museen, Hamburgs Hafen."}},
        {type:"mc",q:"'Der Leiter ___ Abteilung.' Welcher Artikel fehlt?",opts:["der","die","dem","den"],ans:"der",hint:"[AR] Abteilung is feminine. Feminine genitive changes 'die' to 'der.' The head OF the department."},
        {type:"mc",q:"'Die Atmosphäre ___ Hafens ist einzigartig.' Welcher Artikel fehlt?",opts:["den","der","dem","des"],ans:"des",hint:"[AR] Hafen is masculine. Masculine genitive: des + noun + -(e)s."},
        {type:"fb",s:"Der Name {1} Kollegen ist Schmidt.",a:["des"],opts:["des","der","dem","den"],hint:"[AR] Kollege is masculine. Which genitive article goes with masculine nouns?",sSrc:"[AR] The colleague's name is Schmidt."},
        {type:"story",speaker:"verumius",mood:"overwhelmed",art:"de-ham-office",trg:"Herr Professor Doktor Schmidt. Soll ich das jedes Mal sagen? Jedes Mal alle Titel?",src:"[AR] Herr Professor Doktor Schmidt. Am I supposed to say that every time? Every time, all the titles?"},
        {type:"story",speaker:"colleague",mood:"reassuring",art:"de-ham-office-harbor",trg:"Beim ersten Mal: ja. Danach reicht Herr Schmidt. Die Regel ist einfach: lieber zu höflich als zu locker.",src:"[AR] The first time: yes. After that, Herr Schmidt is enough. The rule is simple: better too polite than too casual."}
      ]},
    {id:"deu_r15l4",title:"Der Genitiv und die N-Deklination",icon:"📝",xp:15,board:true,steps:[
        {type:"intro",title:"Der Genitiv und die N-Deklination",desc:"[AR] Master genitive case formation. Learn N-Deklination nouns (der Herr, der Kollege, der Junge). Understand German traffic and driving vocabulary.",goals:[
            "[AR] Practice genitive case formation",
            "[AR] Learn N-Deklination noun patterns",
            "[AR] Master traffic and driving vocabulary",
            "[AR] Combine genitive with N-Deklination"
          ]},
        {type:"teach",trg:"der Gegenstand",src:"[AR] the object / item",pos:"noun",gender:"m",note:"[AR] Gegen (against) + Stand (standing). Something you encounter.",example:"A: Haben Sie persönliche Gegenstände dabei?\nB: Ja, meinen Laptop und mein Handy.\nA: Bitte lassen Sie keine Gegenstände im Zug.\nB: Natürlich.",exampleSrc:"[AR] A: Do you have personal belongings with you?\nB: Yes, my laptop and my phone.\nA: Please do not leave any items on the train.\nB: Of course.",funFact:"[AR] 'Persönliche Gegenstände' (personal belongings) is an announcement you hear on every German train. The word literally means 'against-standing' thing."},
        {type:"teach",trg:"der Geschmack",src:"[AR] the taste / flavor",pos:"noun",gender:"m",note:"[AR] From 'schmecken' (to taste). Also means aesthetic sense.",example:"A: Wie ist der Geschmack?\nB: Sehr gut! Salzig und frisch.\nA: Hamburg hat guten Geschmack beim Essen.\nB: Besonders beim Fisch!",exampleSrc:"[AR] A: How is the taste?\nB: Very good! Salty and fresh.\nA: Hamburg has good taste in food.\nB: Especially with fish!",funFact:"[AR] 'Guter Geschmack' means both good taste in food AND good aesthetic sense. 'Geschmacklos' (tasteless) works the same way: bad-tasting or tacky."},
        {type:"teach",trg:"die Geschwindigkeit",src:"[AR] the speed",pos:"noun",gender:"f",note:"[AR] From 'geschwind' (swift). A famously long word at 17 letters.",example:"A: Wie hoch ist die Geschwindigkeit des ICE?\nB: Bis zu 300 km/h.\nA: Das ist schnell!\nB: Ja, die schnellste Verbindung.",exampleSrc:"[AR] A: How fast is the ICE?\nB: Up to 300 km/h.\nA: That is fast!\nB: Yes, the fastest connection.",funFact:"[AR] On the Autobahn, sections without speed limit are marked 'Keine Geschwindigkeitsbegrenzung.' This word alone is 30 characters of German compound mastery."},
        {type:"teach",trg:"die Geschwindigkeitsbeschränkung",src:"[AR] the speed limit",pos:"noun",gender:"f",note:"[AR] Geschwindigkeit + Beschränkung (restriction). 30 characters long.",example:"A: Gibt es hier eine Geschwindigkeitsbeschränkung?\nB: Ja, Tempo 50.\nA: Und auf der Autobahn?\nB: Manchmal keine!",exampleSrc:"[AR] A: Is there a speed limit here?\nB: Yes, 50 km/h.\nA: And on the Autobahn?\nB: Sometimes none!",funFact:"[AR] This is the word that makes German famous for long compounds. Posted as road signs: '50' in a red circle. Most Germans just say 'Tempolimit' in conversation."},
        {type:"teach",trg:"die Reservierung",src:"[AR] the reservation",pos:"noun",gender:"f",note:"[AR] From 'reservieren.' The -ung suffix is always feminine.",example:"A: Haben Sie eine Reservierung?\nB: Ja, auf den Namen Verumius.\nA: Für zwei Personen?\nB: Ja, genau.",exampleSrc:"[AR] A: Do you have a reservation?\nB: Yes, under the name Verumius.\nA: For two people?\nB: Yes, exactly.",funFact:"[AR] 'Haben Sie eine Reservierung?' is what every hotel and restaurant asks. For trains, you pay extra for a 'Sitzplatzreservierung' (seat reservation)."},
        {type:"teach",trg:"die Rückfahrt",src:"[AR] the return trip",pos:"noun",gender:"f",note:"[AR] Rück (back) + Fahrt (journey). 'Hin- und Rückfahrt' = round trip.",example:"A: Wann ist die Rückfahrt?\nB: Morgen Abend.\nA: Haben Sie ein Ticket für die Rückfahrt?\nB: Ja, eine Hin- und Rückfahrt.",exampleSrc:"[AR] A: When is the return trip?\nB: Tomorrow evening.\nA: Do you have a ticket for the return?\nB: Yes, a round trip.",funFact:"[AR] On train tickets, 'einfach' means one way and 'hin und zurück' means round trip. The Rückfahrt is always the homeward leg."},
        {type:"teach",trg:"die Rundfahrt",src:"[AR] the tour / sightseeing trip",pos:"noun",gender:"f",note:"[AR] Rund (round) + Fahrt (journey). Hamburg's Hafenrundfahrt is iconic.",example:"A: Machen wir eine Rundfahrt?\nB: Ja, eine Hafenrundfahrt!\nA: Wie lange dauert die Rundfahrt?\nB: Etwa eine Stunde.",exampleSrc:"[AR] A: Shall we do a tour?\nB: Yes, a harbor tour!\nA: How long does the tour take?\nB: About one hour.",funFact:"[AR] Hamburg's Hafenrundfahrt (harbor tour) is the city's most popular tourist activity. Small boats navigate between enormous container ships."},
        {type:"teach",trg:"die Umleitung",src:"[AR] the detour",pos:"noun",gender:"f",note:"[AR] Um (around) + Leitung (leading). Yellow signs guide you around construction.",example:"A: Die Straße ist gesperrt!\nB: Es gibt eine Umleitung.\nA: Wohin führt die Umleitung?\nB: Folgen Sie den gelben Schildern.",exampleSrc:"[AR] A: The road is closed!\nB: There is a detour.\nA: Where does the detour lead?\nB: Follow the yellow signs.",funFact:"[AR] On German roads, the yellow 'Umleitung' signs guide you around construction. Germans trust these signs completely, even when the detour seems absurdly long."},
        {type:"teach",trg:"der Umtausch",src:"[AR] the exchange / return (of goods)",pos:"noun",gender:"m",note:"[AR] Um (exchange) + Tausch (swap). Standard retail policy.",example:"A: Ich möchte einen Umtausch machen.\nB: Haben Sie den Kassenbon?\nA: Ja, hier.\nB: Kein Problem. Was möchten Sie umtauschen?",exampleSrc:"[AR] A: I would like to make an exchange.\nB: Do you have the receipt?\nA: Yes, here.\nB: No problem. What would you like to exchange?",funFact:"[AR] 'Umtausch nur mit Kassenbon' (exchange only with receipt) is the standard policy in German retail. No receipt, no exchange, no exceptions."},
        {type:"teach",trg:"die Vorfahrt",src:"[AR] the right of way",pos:"noun",gender:"f",note:"[AR] Vor (before) + Fahrt (driving). The yellow diamond sign means you have it.",example:"A: Wer hat hier Vorfahrt?\nB: Das Schild sagt: Vorfahrt beachten!\nA: Also muss ich warten?\nB: Ja, der andere Fahrer hat Vorfahrt.",exampleSrc:"[AR] A: Who has right of way here?\nB: The sign says: Yield!\nA: So I have to wait?\nB: Yes, the other driver has right of way.",funFact:"[AR] 'Vorfahrt beachten!' (Yield!) is one of the most important road signs. The yellow diamond sign means you have Vorfahrt. Critical for driving in Germany."},
        {type:"teach",trg:"der Halt",src:"[AR] the stop",pos:"noun",gender:"m",note:"[AR] From 'halten' (to stop/hold). On buses and trains: 'Nächster Halt...'",example:"A: Nächster Halt: Jungfernstieg.\nB: Das ist unsere Station!\nA: Schnell, wir müssen aussteigen.\nB: Ich komme!",exampleSrc:"[AR] A: Next stop: Jungfernstieg.\nB: That is our station!\nA: Quick, we have to get off.\nB: I am coming!",funFact:"[AR] 'Nächster Halt' (next stop) is the phrase you hear most on German public transport. Also: 'Halt! Stehenbleiben!' in action movies."},
        {type:"teach",trg:"der Stau",src:"[AR] the traffic jam",pos:"noun",gender:"m",note:"[AR] Germany's Autobahn: famous for no speed limit AND epic traffic jams.",example:"A: Es gibt einen langen Stau auf der A7.\nB: Wie lange müssen wir warten?\nA: Vielleicht eine Stunde.\nB: Dann nehmen wir die Umleitung.",exampleSrc:"[AR] A: There is a long traffic jam on the A7.\nB: How long do we have to wait?\nA: Maybe an hour.\nB: Then let us take the detour.",funFact:"[AR] 'Im Stau stehen' (to be stuck in a traffic jam) is a German national experience. The ADAC (German automobile club) reports Stau updates constantly, especially on holiday weekends."},
        {type:"teach",trg:"die Tankstelle",src:"[AR] the gas station",pos:"noun",gender:"f",note:"[AR] Tank + Stelle (place). Also convenience stores. Open late.",example:"A: Wir müssen tanken.\nB: Wo ist die nächste Tankstelle?\nA: In zwei Kilometern.\nB: Gut, wir haben noch genug Benzin.",exampleSrc:"[AR] A: We need to refuel.\nB: Where is the nearest gas station?\nA: In two kilometers.\nB: Good, we still have enough gasoline.",funFact:"[AR] German Tankstellen are also convenience stores. After 8 PM, they are often the only shops open. 'Tanken' = to refuel. 'Volltanken' = fill it up."},
        {type:"teach",trg:"die Panne",src:"[AR] the breakdown",pos:"noun",gender:"f",note:"[AR] Also used metaphorically: 'Das war eine Panne' = That was a blunder.",example:"A: Wir haben eine Panne!\nB: Was ist passiert?\nA: Der Reifen ist platt.\nB: Rufen Sie den ADAC an!",exampleSrc:"[AR] A: We have a breakdown!\nB: What happened?\nA: The tire is flat.\nB: Call the ADAC!",funFact:"[AR] 'Eine Panne haben' works for both car breakdowns and embarrassing blunders. From French 'panne.' The ADAC is Germany's roadside assistance, like AAA."},
        {type:"teach",trg:"das Tempo",src:"[AR] the speed / pace",pos:"noun",gender:"n",note:"[AR] From Italian 'tempo.' 'Tempo 30' means a 30 km/h zone.",example:"A: Hier ist Tempo 30.\nB: Warum so langsam?\nA: Das ist ein Wohngebiet.\nB: Ach so, wegen der Kinder.",exampleSrc:"[AR] A: This is a 30 km/h zone.\nB: Why so slow?\nA: This is a residential area.\nB: I see, because of the children.",funFact:"[AR] 'Tempo' is also a famous German tissue brand. 'Tempo' is to tissues what Kleenex is in the US. Asking for a 'Tempo' in Germany means asking for a tissue."},
        {type:"teach",trg:"der Salon",src:"[AR] the salon",pos:"noun",gender:"m",note:"[AR] From French 'salon.' 'Friseursalon' = hair salon.",example:"A: Wo ist der Friseursalon?\nB: In der nächsten Straße.\nA: Brauche ich einen Termin?\nB: Nein, einfach hingehen.",exampleSrc:"[AR] A: Where is the hair salon?\nB: In the next street.\nA: Do I need an appointment?\nB: No, just go there.",funFact:"[AR] The word retained its French pronunciation in German. 'Friseursalon' (hair salon), 'Kosmetiksalon' (beauty salon), 'Nagelsalon' (nail salon). All from French."},
        {type:"teach",trg:"eilen",src:"[AR] to hurry",pos:"verb",gender:null,note:"[AR] 'Eilt!' on documents means 'Urgent!' Related to English 'zeal.'",example:"A: Wir müssen eilen!\nB: Warum?\nA: Das Meeting beginnt in fünf Minuten.\nB: Dann los!",exampleSrc:"[AR] A: We have to hurry!\nB: Why?\nA: The meeting starts in five minutes.\nB: Then let's go!",funFact:"[AR] 'Es eilt' (it is urgent) appears on official documents. Related to English 'zeal' via Proto-Germanic. 'Eilzustellung' = express delivery."},
        {type:"teach",trg:"stoppen",src:"[AR] to stop",pos:"verb",gender:null,note:"[AR] From English 'stop.' Regular verb. Also used in sports timing.",example:"A: Stoppen Sie das Auto!\nB: Warum? Was ist passiert?\nA: Eine rote Ampel!\nB: Oh, danke! Ich habe sie nicht gesehen.",exampleSrc:"[AR] A: Stop the car!\nB: Why? What happened?\nA: A red light!\nA: Oh, thanks! I did not see it.",funFact:"[AR] 'Die Zeit stoppen' means to time something with a stopwatch. 'Stopp!' as an interjection means 'Hold on!' or 'Wait!'"},
        {type:"tip",title:"N-Deklination: the special masculine nouns",text:"[AR] Some masculine nouns add -(e)n in EVERY case except nominative. These are N-Deklination nouns.\n\nCommon N-Deklination nouns:\nder Herr, der Kollege, der Junge, der Kunde, der Name, der Student, der Patient, der Nachbar\n\nNominativ: der Herr / der Kollege\nAkkusativ: den Herrn / den Kollegen\nDativ: dem Herrn / dem Kollegen\nGenitiv: des Herrn / des Kollegen\n\nHow to spot them:\n- Masculine nouns ending in -e (Kollege, Junge, Kunde)\n- Endings: -ent (Student, Patient), -ant (Praktikant), -ist (Tourist)\n- The word Herr\n\nFrom the story: 'dem Herrn Kollegen' uses BOTH N-Deklination nouns in dative!",deepDive:{title:"Why N-Deklination exists",text:"[AR] N-Deklination is a remnant of Old German weak noun declension. These nouns were originally 'weak' masculine nouns that took -n in all oblique cases. Over centuries, most nouns lost this pattern, but about 200 common ones kept it.\n\nThe key rule: if you are not sure whether a masculine noun is N-Deklination, check if it ends in -e. Most masculine nouns ending in -e (der Junge, der Kollege, der Kunde, der Nachbar) are N-Deklination."}},
        {type:"verb_table",title:"N-Deklination: der Kollege",groups:[
            {label:"Singular",rows:[
                {pronoun:"Nominativ",form:"der Kollege",src:"the colleague (subject)"},
                {pronoun:"Akkusativ",form:"den Kollegen",src:"the colleague (direct object)"},
                {pronoun:"Dativ",form:"dem Kollegen",src:"to the colleague"},
                {pronoun:"Genitiv",form:"des Kollegen",src:"of the colleague"}
              ]},
            {label:"Vergleich: der Herr",rows:[
                {pronoun:"Nominativ",form:"der Herr",src:"the gentleman"},
                {pronoun:"Akkusativ",form:"den Herrn",src:"the gentleman (direct object)"},
                {pronoun:"Dativ",form:"dem Herrn",src:"to the gentleman"},
                {pronoun:"Genitiv",form:"des Herrn",src:"of the gentleman"}
              ]}
          ],note:"[AR] N-Deklination nouns add -(e)n in every case except nominative. Herr adds just -n, Kollege adds -n."},
        {type:"mc",q:"'Die Lage ___ Hafens ist ideal.' Welcher Artikel passt?",opts:["dem","der","den","des"],ans:"des",hint:"[AR] Hafen is masculine. Masculine genitive uses 'des' and adds -(e)s to the noun."},
        {type:"mc",q:"'Die Geschwindigkeit ___ Fähre ist beeindruckend.' Welcher Artikel fehlt?",opts:["der","die","dem","den"],ans:"der",hint:"[AR] Fähre is feminine. Feminine genitive changes 'die' to 'der.' The speed OF the ferry."},
        {type:"fb",s:"Ich stelle Ihnen den {1} vor.",a:["Kollegen"],opts:["Kollegen","Kollege","Kolleges","Kolleg"],hint:"[AR] Kollege is an N-Deklination noun. In accusative, it adds -n.",sSrc:"[AR] I am introducing the colleague to you."},
        {type:"mc",q:"'Der Name DES ... .' How does 'Herr' look in genitive?",opts:["des Herres","des Herren","des Herrn","des Herrs"],ans:"des Herrn",hint:"[AR] Herr is N-Deklination. It adds -n in every case except nominative."},
        {type:"drag_fill",s:"Der Titel {1} {2} ist sehr lang.",blanks:{"1":"des","2":"Kollegen"},pool:["des","der","dem","Kollegen","Kollege","Kolleges"],hint:"[AR] Kollege is masculine AND N-Deklination. Genitive masculine article + N-Dekl ending.",sSrc:"[AR] The colleague's title is very long."},
        {type:"match",pairs:[
            {trg:"des Mannes",src:"of the man"},
            {trg:"der Frau",src:"of the woman"},
            {trg:"des Kindes",src:"of the child"},
            {trg:"der Kinder",src:"of the children"},
            {trg:"des Kollegen",src:"of the colleague"}
          ]},
        {type:"mc",q:"Auf der Autobahn gibt es einen langen ...",opts:["Umtausch","Stau","Salon","Halt"],ans:"Stau",hint:"[AR] What forms when too many cars are on the road at once?"}
      ]},
    {id:"deu_r15l5",title:"Hamburger Küche",icon:"🍜",xp:15,board:true,steps:[
        {type:"intro",title:"Hamburger Küche",desc:"[AR] Master food and restaurant vocabulary. Practice genitive case in real contexts. Discover regional food differences across Germany.",goals:[
            "[AR] Learn 20 food and restaurant vocabulary words",
            "[AR] Practice genitive case in food contexts",
            "[AR] Discover regional food differences",
            "[AR] Order food in a German restaurant"
          ]},
        {type:"story",speaker:"colleague",mood:"enthusiastic",art:"de-ham-restaurant-harbor",trg:"Nach dem Meeting müssen Sie unbedingt Fischbrötchen probieren. Das ist Hamburger Pflicht!",src:"[AR] After the meeting you absolutely must try a fish sandwich. That is a Hamburg obligation!"},
        {type:"story",speaker:"verumius",mood:"eager",art:"de-ham-restaurant-harbor",trg:"Fischbrötchen? Das klingt gut. Ich habe Hunger wegen des langen Meetings.",src:"[AR] Fish sandwiches? That sounds good. I am hungry because of the long meeting."},
        {type:"teach",trg:"die Speise",src:"[AR] the dish / food",pos:"noun",gender:"f",note:"[AR] Formal and slightly old-fashioned. 'Speisekarte' = menu card.",example:"A: Welche Speisen empfehlen Sie?\nB: Die Fischspeisen sind ausgezeichnet.\nA: Haben Sie auch vegetarische Speisen?\nB: Ja, auf Seite zwei der Speisekarte.",exampleSrc:"[AR] A: Which dishes do you recommend?\nB: The fish dishes are excellent.\nA: Do you also have vegetarian dishes?\nB: Yes, on page two of the menu.",funFact:"[AR] 'Speisekarte' (menu card), 'Speisesaal' (dining hall), 'Speisewagen' (dining car). The word Speise appears everywhere in formal dining contexts."},
        {type:"teach",trg:"der Speisewagen",src:"[AR] the dining car",pos:"noun",gender:"m",note:"[AR] Speise + Wagen (wagon/car). Hot coffee and Currywurst at 250 km/h.",example:"A: Gibt es einen Speisewagen im Zug?\nB: Ja, in Wagen 7.\nA: Kann man dort frühstücken?\nB: Ja, Kaffee und Brötchen.",exampleSrc:"[AR] A: Is there a dining car on the train?\nB: Yes, in car 7.\nA: Can you have breakfast there?\nB: Yes, coffee and rolls.",funFact:"[AR] ICE trains have a 'Bordrestaurant' (on-board restaurant), but older trains called it Speisewagen. Hot coffee at 250 km/h is one of Germany's small luxuries."},
        {type:"teach",trg:"die Vorspeise",src:"[AR] the appetizer / starter",pos:"noun",gender:"f",note:"[AR] Vor (before) + Speise (dish). The dish before the main dish.",example:"A: Möchten Sie eine Vorspeise?\nB: Ja, die Suppe bitte.\nA: Gute Wahl. Und als Hauptgericht?\nB: Den Braten.",exampleSrc:"[AR] A: Would you like an appetizer?\nB: Yes, the soup please.\nA: Good choice. And for the main course?\nB: The roast.",funFact:"[AR] German restaurant menus list in order: Vorspeise (starter), Hauptgericht (main course), Nachspeise (dessert). The Vor/Nach pattern makes it logical."},
        {type:"teach",trg:"die Nachspeise",src:"[AR] the dessert",pos:"noun",gender:"f",note:"[AR] Nach (after) + Speise (dish). The after-dish.",example:"A: Was haben Sie als Nachspeise?\nB: Rote Grütze mit Sahne.\nA: Was ist Rote Grütze?\nB: Ein norddeutsches Dessert mit roten Früchten.",exampleSrc:"[AR] A: What do you have for dessert?\nB: Rote Grütze with cream.\nA: What is Rote Grütze?\nB: A northern German dessert with red berries.",funFact:"[AR] German compound logic: before = Vor-, after = Nach-. Vorspeise/Nachspeise, Vorname/Nachname, Vormittag/Nachmittag. Crystal clear pattern."},
        {type:"teach",trg:"das Dessert",src:"[AR] the dessert (French loan)",pos:"noun",gender:"n",note:"[AR] From French 'desservir' (to clear the table). More cosmopolitan than Nachspeise.",example:"A: Zum Dessert nehme ich das Eis.\nB: Schokolade oder Vanille?\nA: Schokolade, bitte.\nB: Ausgezeichnete Wahl!",exampleSrc:"[AR] A: For dessert I will have the ice cream.\nB: Chocolate or vanilla?\nA: Chocolate, please.\nB: Excellent choice!",funFact:"[AR] On upscale Hamburg menus, you see 'Dessert.' In a traditional Kneipe, it is 'Nachspeise.' The word choice signals the restaurant's formality level."},
        {type:"teach",trg:"das Menü",src:"[AR] the set meal",pos:"noun",gender:"n",note:"[AR] In German, Menü means a SET MEAL, NOT the card listing dishes. The card is 'Speisekarte.'",example:"A: Wir nehmen das Menü.\nB: Das Tagesmenü mit drei Gängen?\nA: Ja, Vorspeise, Hauptgericht und Nachspeise.\nB: Perfekt. Kommt sofort.",exampleSrc:"[AR] A: We will take the set meal.\nB: The daily menu with three courses?\nA: Yes, appetizer, main course and dessert.\nB: Perfect. Coming right up.",funFact:"[AR] Das Menü means a set meal (starter + main + dessert), NOT the card listing dishes. The card is 'Speisekarte.' This false friend catches many English speakers."},
        {type:"teach",trg:"der Braten",src:"[AR] the roast",pos:"noun",gender:"m",note:"[AR] Every region has its signature Braten: Schweinebraten, Sauerbraten.",example:"A: Ich nehme den Braten.\nB: Schweinebraten oder Rinderbraten?\nA: Schweinebraten, bitte.\nB: Mit Gemüse?",exampleSrc:"[AR] A: I will have the roast.\nB: Pork roast or beef roast?\nA: Pork roast, please.\nB: With vegetables?",funFact:"[AR] 'Schweinebraten' (pork roast) is Bavaria's national dish. 'Sauerbraten' (marinated pot roast) comes from the Rhineland. Every region has its signature Braten."},
        {type:"teach",trg:"das Hackfleisch",src:"[AR] the ground meat",pos:"noun",gender:"n",note:"[AR] Hack (chopped) + Fleisch (meat). In northern Germany also called 'Mett.'",example:"A: Ich brauche 500 Gramm Hackfleisch.\nB: Vom Rind oder gemischt?\nA: Gemischt, bitte.\nB: Machen Sie Frikadellen?",exampleSrc:"[AR] A: I need 500 grams of ground meat.\nB: Beef or mixed?\nA: Mixed, please.\nB: Are you making meatballs?",funFact:"[AR] In northern Germany (Hamburg!), raw ground pork on bread is called 'Mettbrötchen.' In Austria, ground meat is called 'Faschiertes.' Same product, different countries."},
        {type:"teach",trg:"das Hühnchen",src:"[AR] the chicken",pos:"noun",gender:"n",note:"[AR] Diminutive of 'Huhn.' The -chen suffix makes it neuter AND small/cute.",example:"A: Ein halbes Hühnchen, bitte.\nB: Mit Pommes?\nA: Ja, und Salat dazu.\nB: Kommt sofort!",exampleSrc:"[AR] A: Half a chicken, please.\nB: With fries?\nA: Yes, and salad on the side.\nB: Coming right up!",funFact:"[AR] The -chen suffix always makes nouns neuter: das Mädchen (the girl), das Hühnchen (the chicken), das Brötchen (the bread roll). Every German supermarket rotisserie has Brathähnchen."},
        {type:"teach",trg:"das Gewürz",src:"[AR] the spice",pos:"noun",gender:"n",note:"[AR] From 'Würze' (seasoning). Plural: Gewürze.",example:"A: Welche Gewürze mögen Sie?\nB: Pfeffer und Paprika.\nA: Hamburg war eine Gewürzhandelsstadt.\nB: Stimmt, wegen des Hafens.",exampleSrc:"[AR] A: Which spices do you like?\nB: Pepper and paprika.\nA: Hamburg was a spice trading city.\nB: True, because of the harbor.",funFact:"[AR] Hamburg's Speicherstadt (warehouse district) stored spices from around the world for centuries. The Gewürzmuseum (spice museum) is still there today."},
        {type:"teach",trg:"der Essig",src:"[AR] the vinegar",pos:"noun",gender:"m",note:"[AR] From Latin 'acetum.' Germans love Essig on salad.",example:"A: Essig und Öl für den Salat?\nB: Ja, bitte. Mehr Essig als Öl.\nA: Sie mögen es sauer?\nB: Ja, sehr!",exampleSrc:"[AR] A: Vinegar and oil for the salad?\nB: Yes, please. More vinegar than oil.\nA: You like it sour?\nB: Yes, very!",funFact:"[AR] 'Essig und Öl' (vinegar and oil) is the standard German salad dressing. Also: 'Es ist Essig!' (slang: It is over/ruined!). A versatile word."},
        {type:"teach",trg:"der Honig",src:"[AR] the honey",pos:"noun",gender:"m",note:"[AR] From Proto-Germanic '*hunagaz.' Related to English 'honey.'",example:"A: Möchten Sie Honig aufs Brot?\nB: Ja, gern! Ist das lokaler Honig?\nA: Ja, vom Imker nebenan.\nB: Lecker!",exampleSrc:"[AR] A: Would you like honey on your bread?\nB: Yes, gladly! Is that local honey?\nA: Yes, from the beekeeper next door.\nB: Delicious!",funFact:"[AR] German breakfast often includes Honig on bread. 'Honigkuchen' (honey cake) is a Christmas specialty. Germany is Europe's largest honey consumer."},
        {type:"teach",trg:"die Soße",src:"[AR] the sauce",pos:"noun",gender:"f",note:"[AR] From French 'sauce.' Written with ß in German (no c).",example:"A: Die Soße ist ausgezeichnet!\nB: Danke! Das ist unsere Hausspezialität.\nA: Was ist drin?\nB: Das ist ein Geheimnis!",exampleSrc:"[AR] A: The sauce is excellent!\nB: Thanks! That is our house specialty.\nA: What is in it?\nB: That is a secret!",funFact:"[AR] 'Bratensoße' (gravy) is essential with every Braten. Hamburg's fish restaurants are famous for their Dillsoße (dill sauce). The word comes from French."},
        {type:"teach",trg:"die Karotte",src:"[AR] the carrot",pos:"noun",gender:"f",note:"[AR] From French 'carotte.' In northern Germany: 'Möhre.'",example:"A: Karotten oder Möhren?\nB: Das ist das Gleiche!\nA: Warum zwei Wörter?\nB: Regional: Karotte im Süden, Möhre im Norden.",exampleSrc:"[AR] A: Karotten or Möhren?\nB: That is the same thing!\nA: Why two words?\nB: Regional: Karotte in the south, Möhre in the north.",funFact:"[AR] Three words for one vegetable: Karotte (south), Möhre (north/Hamburg), gelbe Rübe (some regions). Germany's regional vocabulary in a nutshell."},
        {type:"teach",trg:"die Limonade",src:"[AR] the lemonade / soft drink",pos:"noun",gender:"f",note:"[AR] Short: Limo. In Germany, 'Limo' means ANY sweet carbonated drink.",example:"A: Eine Limo, bitte!\nB: Welche? Zitrone oder Orange?\nA: Zitrone.\nB: Kommt sofort.",exampleSrc:"[AR] A: A soft drink, please!\nB: Which one? Lemon or orange?\nA: Lemon.\nB: Coming right up.",funFact:"[AR] In Germany, 'Limo' means ANY sweet carbonated drink, not just lemon-flavored. Ordering 'eine Limo' at any Kneipe gets you a fizzy soft drink."},
        {type:"teach",trg:"der Imbiss",src:"[AR] the snack bar / quick bite",pos:"noun",gender:"m",note:"[AR] Germany's fast food institution. Currywurst, Döner, Fischbrötchen.",example:"A: Ich habe Hunger. Gibt es hier einen Imbiss?\nB: Ja, an der Ecke.\nA: Was haben die?\nB: Fischbrötchen! Typisch Hamburg.",exampleSrc:"[AR] A: I am hungry. Is there a snack bar here?\nB: Yes, on the corner.\nA: What do they have?\nB: Fish sandwiches! Typical Hamburg.",funFact:"[AR] The Imbiss is Germany's fast food institution. Every corner has one. In Austria, a quick snack is called 'Jause.' In Hamburg, the star Imbiss food is the Fischbrötchen."},
        {type:"teach",trg:"die Kneipe",src:"[AR] the pub / bar",pos:"noun",gender:"f",note:"[AR] Informal, cozy, beer-focused. Hamburg's St. Pauli has legendary ones.",example:"A: Gehen wir in eine Kneipe?\nB: Ja, ich kenne eine gute in St. Pauli.\nA: Was trinken wir?\nB: Ein Astra, das Hamburger Bier!",exampleSrc:"[AR] A: Shall we go to a pub?\nB: Yes, I know a good one in St. Pauli.\nA: What do we drink?\nB: An Astra, the Hamburg beer!",funFact:"[AR] Hamburg's St. Pauli district has legendary Kneipen. 'Kneipe' suggests informal, cozy, beer-focused. Fancier places are called 'Bar' or 'Lounge.'"},
        {type:"teach",trg:"lecker",src:"لذيذ",pos:"adj",gender:null,note:"[AR] The highest food compliment in casual German. From 'lecken' (to lick).",example:"A: Wie schmeckt der Fisch?\nB: Sehr lecker!\nA: Und die Soße?\nB: Auch lecker! Alles ist lecker hier.",exampleSrc:"[AR] A: How does the fish taste?\nB: Very delicious!\nA: And the sauce?\nB: Also delicious! Everything is delicious here.",funFact:"[AR] 'Das ist lecker!' is the universal German food compliment. Something so good you want to lick the plate. From 'lecken' (to lick)."},
        {type:"teach",trg:"salzig",src:"مالح",pos:"adj",gender:null,note:"[AR] From 'Salz' (salt). The -ig suffix turns nouns into adjectives.",example:"A: Die Suppe ist zu salzig.\nB: Wirklich? Ich finde sie gut.\nA: Hamburg und Salz gehören zusammen.\nB: Stimmt, wegen des Meeres!",exampleSrc:"[AR] A: The soup is too salty.\nB: Really? I think it is good.\nA: Hamburg and salt go together.\nB: True, because of the sea!",funFact:"[AR] Hamburg's proximity to the sea means salty air and salty food. The -ig suffix turns nouns into adjectives: Salz/salzig, Hunger/hungrig, Durst/durstig."},
        {type:"teach",trg:"mild",src:"[AR] mild",pos:"adj",gender:null,note:"[AR] Same as English. One of the easiest German adjectives for English speakers.",example:"A: Der Käse ist mild.\nB: Haben Sie auch würzigen Käse?\nA: Ja, den Tilsiter.\nB: Den nehme ich!",exampleSrc:"[AR] A: The cheese is mild.\nB: Do you also have sharp cheese?\nA: Yes, the Tilsiter.\nB: I will take that!",funFact:"[AR] 'Milder Käse' (mild cheese), 'mildes Wetter' (mild weather), 'milde Strafe' (lenient punishment). One of the easiest German words for English speakers."},
        {type:"mc",q:"'Der Geschmack DES Bratens ist ausgezeichnet.' What case is 'des Bratens'?",opts:["Genitive: of the roast","Dative: to the roast","Accusative: the roast","Nominative: the roast"],ans:"Genitive: of the roast",hint:"[AR] Des Bratens uses des + noun + -s. Which case describes possession or 'of the roast'?"},
        {type:"fb",s:"Die Soße {1} Vorspeise war lecker.",a:["der"],opts:["der","die","des","dem"],hint:"[AR] Vorspeise is feminine. Genitive feminine changes die to what?",sSrc:"[AR] The sauce of the appetizer was delicious."},
        {type:"mc",q:"In Hamburg, Karotten are also called ...",opts:["Gewürze","Kartoffeln","Rüben","Möhren"],ans:"Möhren",hint:"[AR] Northern German dialect word for carrots, mentioned in the teach card."},
        {type:"drag_fill",s:"Während {1} {2} bestellen wir die Nachspeise.",blanks:{"1":"des","2":"Essens"},pool:["des","der","dem","Essens","Essen","Esse"],hint:"[AR] Während takes genitive. Essen is neuter: des + -(e)ns.",sSrc:"[AR] During the meal we order the dessert."},
        {type:"match",pairs:[
            {trg:"Vorspeise",src:"appetizer"},
            {trg:"Nachspeise",src:"dessert"},
            {trg:"Braten",src:"roast"},
            {trg:"Hackfleisch",src:"ground meat"},
            {trg:"Gewürz",src:"spice"}
          ]},
        {type:"story",speaker:"verumius",mood:"satisfied",art:"de-ham-restaurant-harbor",trg:"Das Fischbrötchen war lecker. Und die Kollegin sagt Möhre statt Karotte. Jede Region hat ihre eigene Sprache.",src:"[AR] The fish sandwich was delicious. And the colleague says Möhre instead of Karotte. Every region has its own language."}
      ]},
    {id:"deu_r15l6",title:"Elbphilharmonie",icon:"🎶",xp:15,board:true,steps:[
        {type:"intro",title:"Elbphilharmonie",desc:"[AR] Experience Hamburg's most stunning building. Master genitive prepositions: während, wegen, trotz, statt, innerhalb. Practice genitive case in flowing German sentences.",goals:[
            "[AR] Learn genitive prepositions",
            "[AR] Practice genitive in natural contexts",
            "[AR] Master building and hospitality vocabulary",
            "[AR] Experience the Elbphilharmonie through story"
          ]},
        {type:"story",speaker:"narrator",mood:"reflective",art:"de-ham-elbphilharmonie",trg:"Die Elbphilharmonie bei blauer Stunde. Verumius steht auf der Plaza und schaut auf das Glas, das die letzten Strahlen des Tageslichts fängt.",src:"[AR] The Elbphilharmonie at blue hour. Verumius stands on the plaza and looks at the glass catching the last rays of daylight."},
        {type:"story",speaker:"narrator",mood:"contemplative",art:"de-ham-elbphilharmonie",trg:"Trotz des Regens war der Tag ein Erfolg. Während des Meetings hat er professionelles Deutsch gesprochen. Wegen der Reise fühlt er sich stärker.",src:"[AR] Despite the rain, the day was a success. During the meeting he spoke professional German. Because of the trip he feels stronger."},
        {type:"story",speaker:"verumius",mood:"thinking",art:"de-ham-elbphilharmonie",trg:"Innerhalb eines Tages habe ich so viel erlebt. Statt der Angst fühle ich jetzt Stolz.",src:"[AR] Within one day I have experienced so much. Instead of fear I now feel pride."},
        {type:"teach",trg:"die Bar",src:"[AR] the bar",pos:"noun",gender:"f",note:"[AR] From English/French 'bar.' Rooftop bars with harbor views are popular in Hamburg.",example:"A: Gehen wir an die Bar?\nB: Ja, die Bar auf dem Dach!\nA: Man sieht den ganzen Hafen.\nB: Bei Nacht ist es besonders schön.",exampleSrc:"[AR] A: Shall we go to the bar?\nB: Yes, the rooftop bar!\nA: You can see the whole harbor.\nB: At night it is especially beautiful.",funFact:"[AR] Hamburg's HafenCity has rooftop bars with harbor views. 'An der Bar sitzen' (to sit at the bar) is a common evening activity."},
        {type:"teach",trg:"das Buffet",src:"[AR] the buffet",pos:"noun",gender:"n",note:"[AR] From French 'buffet.' 'Frühstücksbuffet' = breakfast buffet.",example:"A: Das Frühstücksbuffet ist toll!\nB: Ja, Brötchen, Käse, Wurst, Müsli.\nA: Und Eier!\nB: Typisch deutsches Frühstück.",exampleSrc:"[AR] A: The breakfast buffet is great!\nB: Yes, rolls, cheese, cold cuts, muesli.\nA: And eggs!\nB: Typical German breakfast.",funFact:"[AR] German hotels are famous for their elaborate breakfast buffets. Also spelled 'Büfett' in older German. Both spellings are correct."},
        {type:"teach",trg:"die Marmelade",src:"[AR] the jam",pos:"noun",gender:"f",note:"[AR] EU regulation: only citrus jam can be 'Marmelade.' Everything else is 'Konfitüre.'",example:"A: Möchten Sie Marmelade?\nB: Ja, Erdbeermarmelade, bitte.\nA: Technisch ist das Konfitüre.\nB: Egal, schmeckt gut!",exampleSrc:"[AR] A: Would you like jam?\nB: Yes, strawberry jam, please.\nA: Technically that is Konfitüre.\nB: Does not matter, tastes good!",funFact:"[AR] EU regulation says only citrus preserves can be called 'Marmelade.' Everything else is technically 'Konfitüre.' But every German still says Marmelade. In Switzerland, 'Konfitüre' is the standard word."},
        {type:"teach",trg:"die Margarine",src:"[AR] the margarine",pos:"noun",gender:"f",note:"[AR] From French. Pronounced 'mar-ga-REE-ne' with stress on the third syllable.",example:"A: Butter oder Margarine?\nB: Margarine, bitte.\nA: Gesund!\nB: Naja, Geschmackssache.",exampleSrc:"[AR] A: Butter or margarine?\nB: Margarine, please.\nA: Healthy!\nB: Well, matter of taste.",funFact:"[AR] Invented as a cheap butter substitute. Pronounced 'mar-ga-REE-ne' in German, with stress on the third syllable. A breakfast-table staple alongside Butter."},
        {type:"teach",trg:"die Wolle",src:"[AR] the wool",pos:"noun",gender:"f",note:"[AR] Same root as English 'wool.' Essential in Hamburg's maritime climate.",example:"A: Diese Jacke ist aus Wolle.\nB: Gut für Hamburg!\nA: Ja, wegen der Kälte.\nB: Wolle hält warm und trocken.",exampleSrc:"[AR] A: This jacket is made of wool.\nB: Good for Hamburg!\nA: Yes, because of the cold.\nB: Wool keeps you warm and dry.",funFact:"[AR] Hamburg's maritime climate means warm Wolle clothing is essential. 'Merinowolle' (merino wool) is a favorite. 'In Wolle gepackt' means bundled up."},
        {type:"teach",trg:"das Leder",src:"[AR] the leather",pos:"noun",gender:"n",note:"[AR] Related to English 'leather.' Lederhosen are Bavarian, not Hamburg.",example:"A: Eine Lederjacke für Hamburg?\nB: Nicht ideal bei Regen.\nA: Stimmt. Lieber eine Regenjacke.\nB: Hamburg ist keine Lederhosen-Stadt!",exampleSrc:"[AR] A: A leather jacket for Hamburg?\nB: Not ideal in rain.\nA: True. Better a rain jacket.\nB: Hamburg is not a Lederhosen city!",funFact:"[AR] Lederhosen (leather pants) are Bavarian tradition, not Hamburg. Hamburg prefers practical rain jackets. 'Echtes Leder' (genuine leather) is a quality marker."},
        {type:"teach",trg:"der Katalog",src:"[AR] the catalog",pos:"noun",gender:"m",note:"[AR] From Greek 'katalogos' (list). Once the backbone of German mail-order shopping.",example:"A: Haben Sie einen Katalog?\nB: Nein, heute ist alles online.\nA: Früher gab es dicke Kataloge.\nB: Ja, der Otto-Katalog war legendär.",exampleSrc:"[AR] A: Do you have a catalog?\nB: No, today everything is online.\nA: In the past there were thick catalogs.\nB: Yes, the Otto catalog was legendary.",funFact:"[AR] The Otto catalog was once Germany's shopping bible. Hamburg-based Otto is still one of the world's largest online retailers. The physical Katalog era ended around 2010."},
        {type:"teach",trg:"die Hütte",src:"[AR] the hut / cabin",pos:"noun",gender:"f",note:"[AR] Related to English 'hut.' 'Berghütte' = mountain cabin, 'Skihütte' = ski lodge.",example:"A: In den Alpen gibt es viele Hütten.\nB: Kann man dort übernachten?\nA: Ja, und essen! Hüttenkäse kommt auch daher.\nB: Wirklich? Interessant!",exampleSrc:"[AR] A: In the Alps there are many cabins.\nB: Can you stay overnight?\nA: Yes, and eat! Cottage cheese also comes from there.\nB: Really? Interesting!",funFact:"[AR] In the Alps, Hütten offer food and shelter to hikers. You can sleep in a Berghütte after a long hike. 'Hüttenkäse' (cottage cheese) literally means cabin cheese."},
        {type:"teach",trg:"die Burg",src:"[AR] the castle / fortress",pos:"noun",gender:"f",note:"[AR] Hamburg = Ham (meadow/bend) + Burg (fortress). Germany has over 25,000.",example:"A: Wissen Sie, woher 'Hamburg' kommt?\nB: Ham + Burg. Eine Burg an der Alster!\nA: Genau! Die Hammaburg.\nB: Die gibt es leider nicht mehr.",exampleSrc:"[AR] A: Do you know where 'Hamburg' comes from?\nB: Ham + Burg. A fortress on the Alster!\nA: Exactly! The Hammaburg.\nB: Unfortunately it no longer exists.",funFact:"[AR] 'Hamburg' literally contains this word: Ham (meadow/bend) + Burg (fortress). Germany has over 25,000 Burgen and Schlösser. Many are now hotels and museums."},
        {type:"teach",trg:"das Hallenbad",src:"[AR] the indoor pool",pos:"noun",gender:"n",note:"[AR] Halle (hall) + Bad (bath/pool). Almost every German town has one.",example:"A: Gibt es hier ein Hallenbad?\nB: Ja, das städtische Hallenbad.\nA: Kann man Bahnen schwimmen?\nB: Ja, 50-Meter-Becken!",exampleSrc:"[AR] A: Is there an indoor pool here?\nB: Yes, the municipal indoor pool.\nA: Can you swim laps?\nB: Yes, 50-meter pool!",funFact:"[AR] Germans love swimming. Almost every town has a Hallenbad (indoor pool) and a Freibad (outdoor pool for summer). Swimming lessons for children are nearly universal."},
        {type:"teach",trg:"das Gasthaus",src:"[AR] the inn / guesthouse",pos:"noun",gender:"n",note:"[AR] Gast (guest) + Haus (house). Traditional German dining: hearty food, local beer.",example:"A: Essen wir im Gasthaus?\nB: Ja, dort gibt es Hausmannskost.\nA: Was ist das?\nB: Traditionelles, deftiges Essen.",exampleSrc:"[AR] A: Shall we eat at the inn?\nB: Yes, they have home cooking there.\nA: What is that?\nB: Traditional, hearty food.",funFact:"[AR] A Gasthaus is more rustic than a Restaurant: hearty food, local beer, wooden furniture. Many German villages have a Gasthaus as their social center."},
        {type:"teach",trg:"die Gaststätte",src:"[AR] the restaurant / eatery",pos:"noun",gender:"f",note:"[AR] Gast + Stätte (place). The official legal term for food-serving establishments.",example:"A: Ist das ein Restaurant oder eine Gaststätte?\nB: Offiziell ist alles eine Gaststätte.\nA: Auch McDonald's?\nB: Ja, gesetzlich gesehen schon!",exampleSrc:"[AR] A: Is that a restaurant or a Gaststätte?\nB: Officially everything is a Gaststätte.\nA: Even McDonald's?\nB: Yes, legally speaking!",funFact:"[AR] On tax forms and business licenses, every restaurant is officially a 'Gaststätte.' The word is bureaucratic German at its finest."},
        {type:"teach",trg:"das Kaffeehaus",src:"[AR] the coffee house",pos:"noun",gender:"n",note:"[AR] Kaffee + Haus. Vienna made the Kaffeehaus world-famous.",example:"A: Gehen wir ins Kaffeehaus?\nB: Hamburg hat tolle Kaffeehäuser.\nA: Hamburg und Kaffee?\nB: Ja! Deutschlands erstes Kaffeehaus war hier, 1677.",exampleSrc:"[AR] A: Shall we go to the coffee house?\nB: Hamburg has great coffee houses.\nA: Hamburg and coffee?\nB: Yes! Germany's first coffee house was here, 1677.",funFact:"[AR] Vienna made the Kaffeehaus world-famous, but Hamburg claims Germany's first one (1677). Coffee culture runs deep in the north. Hamburg is still the center of Germany's coffee trade."},
        {type:"match",pairs:[
            {trg:"die Hütte",src:"the cabin/hut"},
            {trg:"die Burg",src:"the castle"},
            {trg:"das Hallenbad",src:"the indoor pool"},
            {trg:"das Gasthaus",src:"the inn"}
          ]},
        {type:"mc",q:"Was ist der Unterschied zwischen 'Gasthaus' und 'Gaststätte'?",opts:[
            "Gasthaus hat auch Zimmer, Gaststätte nur Essen",
            "Es gibt keinen Unterschied",
            "Gasthaus ist größer",
            "Gaststätte ist teurer"
          ],ans:"Gasthaus hat auch Zimmer, Gaststätte nur Essen",hint:"[AR] One offers accommodation as well as food, the other is primarily a restaurant."}
      ]},
    {id:"deu_r15l7",title:"Wetter und Orientierung",icon:"🌡️",xp:15,board:true,steps:[
        {type:"intro",title:"Wetter und Orientierung",desc:"[AR] Warmth and cold, flat and slippery, turning and braking. Navigate Hamburg with weather vocabulary, direction verbs, and genitive prepositions.",goals:[
            "[AR] Learn weather and texture adjectives",
            "[AR] Master direction verbs: abbiegen, bremsen",
            "[AR] Use genitive prepositions: während, statt"
          ]},
        {type:"teach",trg:"die Wärme",src:"[AR] the warmth",pos:"noun",gender:"f",note:"[AR] From 'warm.' The -e suffix turns adjectives into abstract nouns (always feminine).",example:"A: Die Wärme des Kaffeehauses ist angenehm.\nB: Ja, draussen ist es kalt.\nA: Die Wärme tut gut.\nB: Noch einen Kaffee?",exampleSrc:"[AR] A: The warmth of the coffee house is pleasant.\nB: Yes, outside it is cold.\nA: The warmth feels good.\nB: Another coffee?",funFact:"[AR] The -e suffix turns adjectives into feminine abstract nouns: warm/Wärme, kalt/Kälte, nähe/Nähe, größe/Größe. Always feminine. Very productive pattern."},
        {type:"teach",trg:"die Kälte",src:"[AR] the cold / coldness",pos:"noun",gender:"f",note:"[AR] From 'kalt.' Same pattern as Wärme. Hamburg's maritime cold is wet and windy.",example:"A: Die Kälte ist heute schlimm.\nB: Trotz der Kälte gehen wir raus?\nA: Ja! Die Elbphilharmonie wartet.\nB: Gut, aber mit Wolle!",exampleSrc:"[AR] A: The cold is terrible today.\nB: Despite the cold we go outside?\nA: Yes! The Elbphilharmonie awaits.\nB: Okay, but with wool!",funFact:"[AR] 'Trotz der Kälte' (despite the cold) uses genitive after 'trotz.' Hamburg's maritime Kälte is wet and windy, different from Bavaria's dry mountain cold."},
        {type:"teach",trg:"flach",src:"[AR] flat",pos:"adj",gender:null,note:"[AR] Northern Germany is flach. The opposite of the Alps in the south.",example:"A: Hamburg ist sehr flach.\nB: Ja, keine Berge hier.\nA: Ganz anders als Süddeutschland.\nB: Dafür haben wir das Meer!",exampleSrc:"[AR] A: Hamburg is very flat.\nB: Yes, no mountains here.\nA: Completely different from southern Germany.\nB: But we have the sea!",funFact:"[AR] 'Flachland' (flatland) describes all of northern Germany. The highest point in Hamburg is just 116 meters. Related to English 'flat' via Proto-Germanic."},
        {type:"teach",trg:"glatt",src:"[AR] smooth / slippery",pos:"adj",gender:null,note:"[AR] 'Vorsicht, glatte Straße!' = Caution, slippery road! In winter: 'Glatteis.'",example:"A: Vorsicht, die Straße ist glatt!\nB: Wegen des Regens?\nA: Ja, bei Regen wird alles glatt.\nB: Ich fahre langsam.",exampleSrc:"[AR] A: Caution, the road is slippery!\nB: Because of the rain?\nA: Yes, in rain everything gets slippery.\nB: I am driving slowly.",funFact:"[AR] In winter, 'Glatteis' (black ice) is a serious hazard on German roads. 'Glatteiswarnung' (black ice warning) is a common weather report term."},
        {type:"teach",trg:"abbiegen",src:"[AR] to turn (while driving/walking)",pos:"verb",gender:null,note:"[AR] Ab (off/away) + biegen (to bend). Separable prefix verb.",example:"A: Biegen Sie rechts ab.\nB: Bei der nächsten Kreuzung?\nA: Ja, dann sehen Sie das Gebäude.\nB: Danke!",exampleSrc:"[AR] A: Turn right.\nB: At the next intersection?\nA: Yes, then you will see the building.\nB: Thanks!",funFact:"[AR] Separable: 'Biegen Sie rechts ab' = Turn right. In a subordinate clause, it merges: '...wo ich abbiegen muss.' Essential for giving and following directions."},
        {type:"teach",trg:"bremsen",src:"[AR] to brake",pos:"verb",gender:null,note:"[AR] From 'Bremse' (brake). 'Plötzlich bremsen' = to brake suddenly.",example:"A: Bremsen Sie!\nB: Was ist los?\nA: Ein Fußgänger auf der Fahrbahn!\nB: Gut gesehen! Danke.",exampleSrc:"[AR] A: Brake!\nB: What is wrong?\nA: A pedestrian on the road!\nB: Good eyes! Thanks.",funFact:"[AR] 'Die Bremsen sind gut' (the brakes are good) is an important phrase for car inspections. 'Bremse' also means 'horsefly,' a completely different meaning with the same spelling."},
        {type:"teach",trg:"während",src:"[AR] during, while",pos:"conj",gender:null,note:"[AR] As preposition: während + Genitiv (during).\nAs conjunction: während + verb-final clause (while).",example:"A: Was hast du während des Meetings gemacht?\nB: Ich habe Notizen gemacht.\nA: Während ich schrieb, hat er gesprochen.\nB: Teamarbeit!",exampleSrc:"[AR] A: What did you do during the meeting?\nB: I took notes.\nA: While I was writing, he spoke.\nB: Teamwork!",funFact:"[AR] Während does double duty: as a preposition with genitive (während des Essens) and as a conjunction meaning while (während ich schlief). Both are essential for B1."},
        {type:"teach",trg:"statt",src:"[AR] instead of",pos:"prep",gender:null,note:"[AR] Short form of anstatt. Takes Genitiv.\nStatt des Autos = instead of the car.",example:"A: Statt des Taxis nehmen wir die U-Bahn.\nB: Gute Idee, das spart Geld.\nA: Statt Kaffee trinke ich Tee.\nB: Auch gesünder!",exampleSrc:"[AR] A: Instead of the taxi we take the subway.\nB: Good idea, that saves money.\nA: Instead of coffee I drink tea.\nB: Also healthier!",funFact:"[AR] Statt is the short form of anstatt. Both are correct. As a preposition it takes genitive. As part of statt...zu it creates infinitive clauses meaning instead of doing."},
        {type:"teach",trg:"sich befinden",src:"[AR] to be located, to be situated",pos:"verb",gender:null,note:"[AR] Reflexive. Formal alternative to sein for location.\nDas Hotel befindet sich am Hafen.",example:"A: Wo befindet sich die Elbphilharmonie?\nB: Sie befindet sich in der HafenCity.\nA: Und der Hauptbahnhof?\nB: Er befindet sich im Zentrum.",exampleSrc:"[AR] A: Where is the Elbphilharmonie located?\nB: It is located in the HafenCity.\nA: And the main train station?\nB: It is located in the center.",funFact:"[AR] More formal than sein for describing locations. Das Museum befindet sich in der Altstadt sounds more official. Essential for giving directions and reading maps."},
        {type:"tip",title:"Genitive prepositions: während, wegen, trotz, statt, innerhalb",text:"[AR] These five prepositions ALWAYS take genitive. They elevate your German from everyday to professional.\n\n- während (during): Während des Meetings (during the meeting)\n- wegen (because of): Wegen des Regens (because of the rain)\n- trotz (despite): Trotz der Kälte (despite the cold)\n- statt/anstatt (instead of): Statt des Taxis (instead of the taxi)\n- innerhalb (within): Innerhalb eines Tages (within one day)\n\nThe genitive article depends on gender:\n- Masculine and neuter nouns use des, and the noun gets an -(e)s ending.\n- Feminine and plural nouns use der, with no change to the noun.\n\nIn casual speech, Germans sometimes use dative after wegen/trotz ('wegen dem Regen'), but written and professional German demands genitive.",deepDive:{title:"More genitive prepositions",text:"[AR] Beyond the big five, there are more genitive prepositions:\n\naußerhalb = outside of: Außerhalb der Stadt (outside the city)\noberhalb = above: Oberhalb des Hafens (above the harbor)\nunterhalb = below: Unterhalb der Brücke (below the bridge)\naufgrund = on the basis of: Aufgrund des Wetters (due to the weather)\nanhand = by means of: Anhand der Daten (based on the data)\n\nThe big five (während, wegen, trotz, statt, innerhalb) are the most common and the ones tested on exams."}},
        {type:"mc",q:"'Trotz DES Regens war der Tag gut.' Why 'des Regens'?",opts:[
            "trotz takes genitive; Regen is masculine",
            "trotz takes dative; Regen is neuter",
            "des is always used with weather",
            "trotz takes accusative"
          ],ans:"trotz takes genitive; Regen is masculine",hint:"[AR] Trotz always takes the same case as wegen and während. Regen is masculine, so the article is des + -(e)s."},
        {type:"fb",s:"Während {1} Meetings sprach Verumius Deutsch.",a:["des"],opts:["des","dem","der","das"],hint:"[AR] Während takes genitive. Meeting is neuter. Neuter genitive article?",sSrc:"[AR] During the meeting Verumius spoke German."},
        {type:"mc",q:"Verumius nahm die U-Bahn ___ des Taxis.",opts:["trotz","innerhalb","statt","während"],ans:"statt",hint:"[AR] He chose the subway INSTEAD OF the taxi. Which preposition means 'instead of'?"},
        {type:"drag_fill",s:"{1} {2} Tages hat Verumius viel erlebt.",blanks:{"1":"Innerhalb","2":"eines"},pool:["Innerhalb","Während","eines","des","einem","ein"],hint:"[AR] Within ONE day. Genitive preposition + indefinite genitive article for masculine/neuter.",sSrc:"[AR] Within one day Verumius experienced a lot."},
        {type:"match",pairs:[
            {trg:"während",src:"during"},
            {trg:"wegen",src:"because of"},
            {trg:"trotz",src:"despite"},
            {trg:"statt",src:"instead of"},
            {trg:"innerhalb",src:"within"}
          ]},
        {type:"story",speaker:"narrator",mood:"serene",art:"de-ham-elbphilharmonie-night",trg:"Die Lichter der Elbphilharmonie spiegeln sich im Wasser. Verumius geht langsam die Stufen hinunter, zurück in die Stadt.",src:"[AR] The lights of the Elbphilharmonie reflect on the water. Verumius walks slowly down the steps, back into the city."},
        {type:"story",speaker:"verumius",mood:"content",art:"de-ham-hafencity-night",trg:"Während eines einzigen Tages habe ich mehr erlebt als während einer ganzen Woche in Berlin. Hamburg, du bist besonders.",src:"[AR] During a single day I have experienced more than during an entire week in Berlin. Hamburg, you are special."}
      ]},
    {id:"deu_r15l8",title:"Alles über Hamburg",icon:"🏆",xp:15,board:true,steps:[
        {type:"intro",title:"Alles über Hamburg",desc:"[AR] Test everything from Unit 15. Prove you can use genitive case, N-Deklination, and genitive prepositions. Show mastery of travel, food, and urban vocabulary.",goals:[
            "[AR] Test genitive case mastery",
            "[AR] Test N-Deklination mastery",
            "[AR] Test genitive prepositions",
            "[AR] Assess all unit vocabulary"
          ]},
        {type:"story",speaker:"narrator",mood:"determined",art:"de-ham-hotel-morning",trg:"Letzter Morgen in Hamburg. Der Koffer steht neben der Tür. Verumius trinkt den letzten Kaffee des Aufenthalts und denkt: Ich bin bereit.",src:"[AR] Last morning in Hamburg. The suitcase stands by the door. Verumius drinks the last coffee of the stay and thinks: I am ready."},
        {type:"teach",trg:"das Benzin",src:"[AR] the gasoline / petrol",pos:"noun",gender:"n",note:"[AR] From the chemical compound 'benzene.' 'Bleifrei' = unleaded.",example:"A: Wir brauchen Benzin.\nB: Ist die Tankstelle weit?\nA: Nein, nur zwei Kilometer.\nB: Super oder Diesel?",exampleSrc:"[AR] A: We need gasoline.\nB: Is the gas station far?\nA: No, only two kilometers.\nB: Premium or diesel?",funFact:"[AR] Named after the chemical compound benzene, which was named after a tree resin. 'Super' and 'Diesel' are the common pump labels at German Tankstellen."},
        {type:"teach",trg:"die Bremse",src:"[AR] the brake",pos:"noun",gender:"f",note:"[AR] Also means 'horsefly.' Completely different meaning, same spelling.",example:"A: Die Bremse funktioniert nicht!\nB: Das ist gefährlich!\nA: Wir müssen zur Werkstatt.\nB: Sofort!",exampleSrc:"[AR] A: The brake does not work!\nB: That is dangerous!\nA: We need to go to the workshop.\nB: Immediately!",funFact:"[AR] 'Handbremse' = handbrake, 'Bremse ziehen' = pull the brake. The word also means 'horsefly,' a completely unrelated meaning with the same spelling."},
        {type:"teach",trg:"das Boot",src:"[AR] the boat",pos:"noun",gender:"n",note:"[AR] Same root as English 'boat.' The famous submarine film 'Das Boot' (1981).",example:"A: Fahren wir mit dem Boot?\nB: Ja, ein Ruderboot auf der Alster!\nA: Kann man die Alster mit dem Boot erkunden?\nB: Ja, das ist sehr beliebt in Hamburg.",exampleSrc:"[AR] A: Shall we go by boat?\nB: Yes, a rowboat on the Alster!\nA: Can you explore the Alster by boat?\nB: Yes, that is very popular in Hamburg.",funFact:"[AR] The famous submarine film 'Das Boot' (1981) made this word internationally known. In Hamburg, 'Boot' usually means the small boats on the Alster lake."},
        {type:"teach",trg:"der Gehsteig",src:"[AR] the sidewalk",pos:"noun",gender:"m",note:"[AR] Geh (walk) + Steig (path). Austrian/southern German. North: 'Bürgersteig.'",example:"A: Bleiben Sie auf dem Gehsteig!\nB: In Hamburg sagt man Bürgersteig.\nA: Und in der Schweiz?\nB: Trottoir!",exampleSrc:"[AR] A: Stay on the sidewalk!\nB: In Hamburg they say Bürgersteig.\nA: And in Switzerland?\nB: Trottoir!",funFact:"[AR] Gehsteig (Austria/south), Bürgersteig (north), Trottoir (Switzerland). Three words for the same strip of pavement. A perfect example of regional vocabulary."},
        {type:"teach",trg:"das Verkehrszeichen",src:"[AR] the traffic sign",pos:"noun",gender:"n",note:"[AR] Verkehr (traffic) + Zeichen (sign). Germany has over 1,000 different ones.",example:"A: Was bedeutet dieses Verkehrszeichen?\nB: Vorfahrt beachten.\nA: Deutschland hat so viele Verkehrszeichen!\nB: Über 1.000 verschiedene!",exampleSrc:"[AR] A: What does this traffic sign mean?\nB: Yield.\nA: Germany has so many traffic signs!\nB: Over 1,000 different ones!",funFact:"[AR] Germany has over 1,000 different Verkehrszeichen. There is even a Verkehrszeichenkatalog (traffic sign catalog). For the driving test, you need to know the most important 200."},
        {type:"teach",trg:"die Landung",src:"[AR] the landing",pos:"noun",gender:"f",note:"[AR] From 'landen' (to land). The -ung suffix (always feminine) turns verbs into nouns.",example:"A: Die Landung war sanft.\nB: Gott sei Dank!\nA: Hamburg-Fuhlsbüttel ist ein kleiner Flughafen.\nB: Aber modern.",exampleSrc:"[AR] A: The landing was smooth.\nB: Thank God!\nA: Hamburg-Fuhlsbüttel is a small airport.\nB: But modern.",funFact:"[AR] 'Notlandung' = emergency landing, 'Mondlandung' = moon landing. The -ung suffix turns verbs into feminine nouns: landen/Landung, landen/Landung. Reliable pattern."},
        {type:"teach",trg:"das Fundbüro",src:"[AR] the lost and found office",pos:"noun",gender:"n",note:"[AR] Fund (find) + Büro (office). Every German city has one.",example:"A: Ich habe meinen Regenschirm verloren!\nB: Gehen Sie zum Fundbüro.\nA: Wo ist das?\nB: Im Hauptbahnhof.",exampleSrc:"[AR] A: I lost my umbrella!\nB: Go to the lost and found.\nA: Where is it?\nB: In the main station.",funFact:"[AR] Every German city has a Fundbüro. Left your umbrella on the train? Check the Fundbüro at the Hauptbahnhof. Germans are surprisingly good at turning in found items."},
        {type:"teach",trg:"die Semmel",src:"[AR] the bread roll",pos:"noun",gender:"f",note:"[AR] In Bavaria and Austria: Semmel. In northern Germany: Brötchen.",example:"A: Zwei Semmeln, bitte.\nB: In Hamburg sagen wir Brötchen!\nA: Und in Berlin?\nB: Schrippe! Ein Brötchen, drei Namen.",exampleSrc:"[AR] A: Two bread rolls, please.\nB: In Hamburg we say Brötchen!\nA: And in Berlin?\nB: Schrippe! One roll, three names.",funFact:"[AR] One bread roll, many names: Brötchen (north), Semmel (Bavaria/Austria), Schrippe (Berlin), Weck (southwest), Weggli (Switzerland). Germany's greatest linguistic debate."},
        {type:"teach",trg:"der Knödel",src:"[AR] the dumpling",pos:"noun",gender:"m",note:"[AR] Bavarian and Austrian classic. Not common in Hamburg.",example:"A: Was sind Knödel?\nB: Kugeln aus Kartoffel- oder Brotteig.\nA: Gibt es die in Hamburg?\nB: Selten. Knödel sind eher süddeutsch.",exampleSrc:"[AR] A: What are dumplings?\nB: Balls made of potato or bread dough.\nA: Are there any in Hamburg?\nB: Rarely. Dumplings are more southern German.",funFact:"[AR] 'Kartoffelknödel' (potato dumpling) and 'Semmelknödel' (bread dumpling) are Bavarian/Austrian classics. In Hamburg, you are more likely to find Fischbrötchen."},
        {type:"teach",trg:"die Sahne",src:"[AR] the cream",pos:"noun",gender:"f",note:"[AR] Northern German word. Austrian: 'Obers.' Swiss: 'Rahm.'",example:"A: Mit Sahne?\nB: Ja, bitte!\nA: In Österreich heißt das Obers.\nB: Und in der Schweiz: Rahm.",exampleSrc:"[AR] A: With cream?\nB: Yes, please!\nA: In Austria that is called Obers.\nB: And in Switzerland: Rahm.",funFact:"[AR] Sahne (Germany/north), Obers (Österreich/Austria), Rahm (Schweiz/Switzerland). Same product, three countries, three words."},
        {type:"teach",trg:"die Schlagsahne",src:"[AR] the whipped cream",pos:"noun",gender:"f",note:"[AR] Schlag (whip/hit) + Sahne (cream). Standard German term.",example:"A: Kuchen mit Schlagsahne, bitte!\nB: Gern! Viel oder wenig?\nA: Viel!\nB: Ein wahrer Genießer!",exampleSrc:"[AR] A: Cake with whipped cream, please!\nB: Gladly! A lot or a little?\nA: A lot!\nB: A true connoisseur!",funFact:"[AR] On every German cafe menu next to cake: 'mit Schlagsahne.' In Austria: 'Schlagobers.' In Switzerland: 'Schlagrahm.' One product, three words."},
        {type:"teach",trg:"das Müsli",src:"[AR] the muesli",pos:"noun",gender:"n",note:"[AR] From Swiss German 'Mus' (puree). Now a German breakfast staple.",example:"A: Was frühstücken Sie?\nB: Müsli mit Joghurt.\nA: Selbst gemacht?\nB: Nein, aus dem Supermarkt.",exampleSrc:"[AR] A: What do you have for breakfast?\nB: Muesli with yogurt.\nA: Homemade?\nB: No, from the supermarket.",funFact:"[AR] Originally 'Birchermüsli,' invented by Swiss doctor Maximilian Bircher-Brenner around 1900. Now a German breakfast staple. Swiss spelling: Müesli."},
        {type:"teach",trg:"anschnallen",src:"[AR] to buckle up",pos:"verb",gender:null,note:"[AR] An (on) + schnallen (to buckle). Separable: 'Schnall dich an!'",example:"A: Bitte anschnallen!\nB: Natürlich.\nA: Auf der Autobahn ist es Pflicht.\nB: In Deutschland nimmt man das ernst.",exampleSrc:"[AR] A: Please buckle up!\nB: Of course.\nA: On the Autobahn it is mandatory.\nB: In Germany they take that seriously.",funFact:"[AR] 'Bitte anschnallen!' is the phrase on every flight and Autobahn sign. Germans take seatbelts seriously. Fines for not wearing one: 30 euros."},
        {type:"teach",trg:"hupen",src:"[AR] to honk",pos:"verb",gender:null,note:"[AR] 'Hupen verboten!' = Honking forbidden! Common sign near hospitals.",example:"A: Warum hupen Sie?\nB: Der Radfahrer hat mich nicht gesehen!\nA: Hupen Sie nicht so laut.\nB: Entschuldigung.",exampleSrc:"[AR] A: Why are you honking?\nB: The cyclist did not see me!\nA: Do not honk so loudly.\nB: Sorry.",funFact:"[AR] Germans consider unnecessary Hupen extremely rude. 'Hupen verboten!' signs are common near hospitals. Road rage by horn is frowned upon."},
        {type:"teach",trg:"landen",src:"[AR] to land",pos:"verb",gender:null,note:"[AR] Regular verb. From 'Land.' Also figurative: 'Wo bist du gelandet?'",example:"A: Das Flugzeug landet in Hamburg.\nB: Wann genau?\nA: In zehn Minuten.\nB: Perfekt, wir sind pünktlich.",exampleSrc:"[AR] A: The airplane is landing in Hamburg.\nB: When exactly?\nA: In ten minutes.\nB: Perfect, we are on time.",funFact:"[AR] Also used figuratively: 'Wo bist du gelandet?' = Where did you end up? Uses 'sein' in perfect tense: 'Das Flugzeug ist gelandet.'"},
        {type:"teach",trg:"losfahren",src:"[AR] to depart / set off",pos:"verb",gender:null,note:"[AR] Los (off/away) + fahren (to drive). Separable. 'Los!' = Go!",example:"A: Wann fahren wir los?\nB: Um acht Uhr.\nA: Früh!\nB: Ja, die Strecke ist lang.",exampleSrc:"[AR] A: When do we set off?\nB: At eight o'clock.\nA: Early!\nB: Yes, the route is long.",funFact:"[AR] 'Los!' alone means 'Go!' Germans shout it at sports events. Separable: 'Wir fahren um 8 Uhr los.' Very common in everyday speech."},
        {type:"teach",trg:"stehenbleiben",src:"[AR] to stop / stand still",pos:"verb",gender:null,note:"[AR] Stehen (to stand) + bleiben (to stay). Separable: 'Bleib stehen!'",example:"A: Bitte stehenbleiben!\nB: Warum?\nA: Das Foto ist noch nicht fertig.\nB: Oh, Entschuldigung. Ich bleibe stehen.",exampleSrc:"[AR] A: Please stand still!\nB: Why?\nA: The photo is not done yet.\nB: Oh, sorry. I will stand still.",funFact:"[AR] 'Bleib stehen!' is one of the most common commands. Also used by police: 'Stehenbleiben!' Used in everyday life when someone is about to walk into danger."},
        {type:"teach",trg:"tanken",src:"[AR] to refuel",pos:"verb",gender:null,note:"[AR] From 'Tank.' 'Volltanken' = to fill up completely.",example:"A: Wir müssen tanken.\nB: Die nächste Tankstelle ist in fünf Kilometern.\nA: Reicht das Benzin?\nB: Gerade so.",exampleSrc:"[AR] A: We need to refuel.\nB: The next gas station is in five kilometers.\nA: Is the gasoline enough?\nB: Just barely.",funFact:"[AR] 'Volltanken' = fill it up. Also slang: 'Energie tanken' = to recharge your energy. 'Sonne tanken' = to soak up the sun. Versatile verb."},
        {type:"teach",trg:"überfahren",src:"[AR] to run over",pos:"verb",gender:null,note:"[AR] Inseparable prefix. 'Eine rote Ampel überfahren' = to run a red light.",example:"A: Er hat die rote Ampel überfahren!\nB: Das ist sehr gefährlich.\nA: Und verboten!\nB: Ja, hohe Strafe.",exampleSrc:"[AR] A: He ran the red light!\nB: That is very dangerous.\nA: And forbidden!\nB: Yes, heavy fine.",funFact:"[AR] Inseparable prefix: 'Er hat die Ampel überfahren' (no ge-). 'Eine rote Ampel überfahren' = to run a red light. Serious offense with heavy fines."},
        {type:"teach",trg:"überholen",src:"[AR] to overtake / pass",pos:"verb",gender:null,note:"[AR] Inseparable prefix. 'Rechts überholen ist verboten' on the Autobahn.",example:"A: Darf ich hier überholen?\nB: Nein, Überholverbot!\nA: Und auf der Autobahn?\nB: Nur links überholen!",exampleSrc:"[AR] A: May I overtake here?\nB: No, no-passing zone!\nA: And on the Autobahn?\nB: Only overtake on the left!",funFact:"[AR] 'Rechts überholen ist verboten' (passing on the right is forbidden) is a cardinal rule of the Autobahn. Violators face heavy fines."},
        {type:"mc",q:"'Die Atmosphäre DES Hafens ist besonders.' Which case?",opts:["Accusative masculine","Genitive masculine","Nominative neuter","Dative masculine"],ans:"Genitive masculine",hint:"[AR] Des + noun ending in -s: the classic signal for this case and gender combination."},
        {type:"mc",q:"'Wegen DER Kälte blieb Verumius im Kaffeehaus.' Why 'der'?",opts:[
            "Der is nominative masculine here",
            "Wegen takes genitive; Kälte is feminine",
            "Wegen takes dative; Kälte is feminine",
            "Kälte is always 'der'"
          ],ans:"Wegen takes genitive; Kälte is feminine",hint:"[AR] Kälte is feminine. What does die become in the case required by wegen?"},
        {type:"fb",s:"Der Titel des {1} war 'Professor Doktor.'",a:["Herrn"],opts:["Herrn","Herr","Herrs","Herren"],hint:"[AR] Herr is N-Deklination. In genitive, it adds -n after 'des.'",sSrc:"[AR] The gentleman's title was 'Professor Doktor.'"},
        {type:"mc",q:"'___ des schlechten Wetters ging Verumius zur Elbphilharmonie.'",opts:["Während","Wegen","Statt","Trotz"],ans:"Trotz",hint:"[AR] He went DESPITE the bad weather. Which preposition means 'despite'?"},
        {type:"drag_fill",s:"{1} {2} Reise lernte Verumius viel über Hamburg.",blanks:{"1":"Während","2":"der"},pool:["Während","Trotz","der","des","dem","die"],hint:"[AR] During THE trip. Reise is feminine. Genitive feminine article?",sSrc:"[AR] During the trip Verumius learned a lot about Hamburg."},
        {type:"fb",s:"Die Rundfahrt durch den Hafen {1} Stadt war wunderbar.",a:["der"],opts:["der","die","des","dem"],hint:"[AR] Stadt is feminine. Genitive feminine: die becomes what?",sSrc:"[AR] The tour through the city's harbor was wonderful."},
        {type:"match",pairs:[
            {trg:"Während des Fluges",src:"During the flight"},
            {trg:"Wegen des Nebels",src:"Because of the fog"},
            {trg:"Trotz der Kälte",src:"Despite the cold"},
            {trg:"Statt des Zuges",src:"Instead of the train"},
            {trg:"Innerhalb der Stadt",src:"Within the city"}
          ]},
        {type:"mc",q:"Verumius muss tanken. Where does he go?",opts:["Zur Tankstelle","Zum Hallenbad","Zum Fundbüro","Zur Gaststätte"],ans:"Zur Tankstelle",hint:"[AR] Tanken means to refuel. Where do you get fuel?"},
        {type:"drag_fill",s:"{1} des Meetings stellte man Verumius dem {2} vor.",blanks:{"1":"Während","2":"Kollegen"},pool:["Während","Trotz","Kollegen","Kollege","Kolleg","Herrn"],hint:"[AR] First blank: which preposition means 'during'? Second blank: N-Deklination noun in dative after 'dem.'",sSrc:"[AR] During the meeting Verumius was introduced to the colleague."},
        {type:"story",speaker:"verumius",mood:"proud",art:"de-ham-hotel-checkout",trg:"Trotz der Nervosität habe ich alles richtig gemacht. Den Genitiv, die Titel, sogar das Fischbrötchen.",src:"[AR] Despite the nervousness I did everything right. The genitive, the titles, even the fish sandwich."}
      ]},
    {id:"deu_r15l9",title:"Zurück nach Berlin",icon:"🌃",xp:15,board:true,steps:[
        {type:"intro",title:"Zurück nach Berlin",desc:"[AR] Reflect on the Hamburg trip. Learn direction and movement vocabulary. Discover Germany's regional vocabulary differences. Master the unit's grammar in a final cultural context.",goals:[
            "[AR] Learn direction and movement vocabulary",
            "[AR] Discover regional vocabulary differences",
            "[AR] Practice all unit grammar in cultural context",
            "[AR] Reflect on the Hamburg experience"
          ]},
        {type:"story",speaker:"narrator",mood:"peaceful",art:"de-ham-ice-night",trg:"Der ICE fährt durch die Nacht. Draußen: dunkle Felder, ferne Dorflichter. Verumius schreibt in sein Notizbuch.",src:"[AR] The ICE travels through the night. Outside: dark fields, distant village lights. Verumius writes in his notebook."},
        {type:"story",speaker:"verumius",mood:"reflective",art:"de-ham-ice-night",trg:"Trotz des Regens, trotz der Nervosität war es ein guter Tag. Der Name des Professors war schwer zu merken, aber sein Lächeln war echt.",src:"[AR] Despite the rain, despite the nervousness, it was a good day. The professor's name was hard to remember, but his smile was genuine."},
        {type:"story",speaker:"verumius",mood:"thoughtful",art:"de-ham-ice-night",trg:"Moin. Ein Wort, vier Buchstaben, und plötzlich fühlt sich eine fremde Stadt wie ein Zuhause an.",src:"[AR] Moin. One word, four letters, and suddenly a foreign city feels like a home."},
        {type:"story",speaker:"narrator",mood:"warm",art:"de-ber-hauptbahnhof-night",trg:"Berlin Hauptbahnhof. Auf dem Bahnsteig: ein bekanntes Gesicht. Lukas mit einem Paket unter dem Arm.",src:"[AR] Berlin Central Station. On the platform: a familiar face. Lukas with a package under his arm."},
        {type:"story",speaker:"lukas",mood:"friendly",art:"de-ber-hauptbahnhof-night",trg:"Hey! Wie war Hamburg?",src:"[AR] Hey! How was Hamburg?"},
        {type:"story",speaker:"verumius",mood:"amused",art:"de-ber-hauptbahnhof-night",trg:"Regnerisch.",src:"[AR] Rainy."},
        {type:"story",speaker:"lukas",mood:"laughing",art:"de-ber-hauptbahnhof-night",trg:"Hamburg halt. Komm, wir nehmen die S-Bahn zusammen.",src:"[AR] Hamburg, of course. Come on, let's take the S-Bahn together."},
        {type:"story",speaker:"verumius",mood:"grateful",art:"de-ber-sbahn-night",trg:"Lukas, wusstest du, dass man in Hamburg immer alle Titel sagen muss? Herr Professor Doktor.",src:"[AR] Lukas, did you know that in Hamburg you always have to say all the titles? Herr Professor Doktor."},
        {type:"story",speaker:"lukas",mood:"amused",art:"de-ber-sbahn-night",trg:"In Berlin sagen wir einfach 'Hey.' Willkommen zurück, Verumius.",src:"[AR] In Berlin we just say 'Hey.' Welcome back, Verumius."},
        {type:"teach",trg:"pauschal",src:"[AR] flat-rate / all-inclusive",pos:"adj",gender:null,note:"[AR] 'Pauschalreise' = package tour. From French 'forfait.'",example:"A: Ist das ein Pauschalangebot?\nB: Ja, Hotel, Flüge und Essen inklusive.\nA: Was kostet die Pauschalreise?\nB: 899 Euro pro Person.",exampleSrc:"[AR] A: Is that an all-inclusive offer?\nB: Yes, hotel, flights and food included.\nA: What does the package tour cost?\nB: 899 euros per person.",funFact:"[AR] 'Pauschalreise' (package tour) is very popular in Germany. Germans are among the world's most enthusiastic tourists. 'Pauschal bezahlen' = to pay a flat rate."},
        {type:"teach",trg:"vorder",src:"[AR] front / forward",pos:"adj",gender:null,note:"[AR] 'Der vordere Teil des Zuges' = the front part of the train.",example:"A: Sitzen wir im vorderen Teil?\nB: Ja, Wagen 1.\nA: Das ist besser bei kurzen Halten.\nB: Stimmt, näher am Ausgang.",exampleSrc:"[AR] A: Are we sitting in the front section?\nB: Yes, car 1.\nA: That is better for short stops.\nB: True, closer to the exit.",funFact:"[AR] Comparative of 'vorn' (in front). 'Vorderseite' = front side, 'Vordertür' = front door, 'Vorderrad' = front wheel. Very productive compound element."},
        {type:"teach",trg:"abwärts",src:"[AR] downward",pos:"adv",gender:null,note:"[AR] Ab (away/down) + -wärts (toward). Also figurative: 'Es geht abwärts.'",example:"A: Es geht abwärts.\nB: Wirklich? Bergab?\nA: Nein, ich meine die Wirtschaft.\nB: Ach so, leider.",exampleSrc:"[AR] A: Things are going downhill.\nB: Really? Downhill?\nA: No, I mean the economy.\nB: I see, unfortunately.",funFact:"[AR] The -wärts suffix indicates direction: abwärts (downward), aufwärts (upward), rückwärts (backward), vorwärts (forward). A useful pattern."},
        {type:"teach",trg:"aufwärts",src:"[AR] upward",pos:"adv",gender:null,note:"[AR] Auf (up) + -wärts. Opposite of abwärts.",example:"A: Die Karriere geht aufwärts!\nB: Gut gemacht!\nA: Danke. Wegen der Hamburg-Reise.\nB: Siehst du, es hat sich gelohnt.",exampleSrc:"[AR] A: The career is going up!\nB: Well done!\nA: Thanks. Because of the Hamburg trip.\nB: See, it was worth it.",funFact:"[AR] 'Es geht aufwärts!' (Things are looking up!) is an optimistic expression. Opposite of 'Es geht abwärts.' The -wärts direction pattern is productive."},
        {type:"teach",trg:"außen",src:"[AR] outside",pos:"adv",gender:null,note:"[AR] Opposite of 'innen' (inside). 'Außenseiter' = outsider.",example:"A: Von außen sieht das Gebäude klein aus.\nB: Aber innen ist es riesig!\nA: Außen alt, innen modern.\nB: Typisch Hamburg.",exampleSrc:"[AR] A: From the outside the building looks small.\nB: But inside it is enormous!\nA: Old outside, modern inside.\nB: Typical Hamburg.",funFact:"[AR] Hamburg's Außenalster (Outer Alster lake) is a famous landmark. 'Außenseiter' (outsider) literally means 'outside-sitter.' Opposite: 'innen' (inside)."},
        {type:"teach",trg:"quer",src:"[AR] across / diagonally",pos:"adv",gender:null,note:"[AR] 'Quer durch die Stadt' = across the city. Related to English 'queer.'",example:"A: Wir fahren quer durch Hamburg.\nB: Von Altona bis Wandsbek?\nA: Ja, quer durch die ganze Stadt.\nB: Das dauert eine Stunde.",exampleSrc:"[AR] A: We are going across Hamburg.\nB: From Altona to Wandsbek?\nA: Yes, across the entire city.\nB: That takes an hour.",funFact:"[AR] 'Querstraße' = cross street. 'Quereinstieg' = lateral entry. Related to English 'queer' (originally meaning 'oblique/odd')."},
        {type:"teach",trg:"rauf",src:"[AR] up (colloquial)",pos:"adv",gender:null,note:"[AR] Short for 'herauf.' Colloquial. The prefix rauf- attaches to verbs.",example:"A: Komm rauf!\nB: Ich komme! Welches Stockwerk?\nA: Drittes.\nB: Gibt es keinen Aufzug?",exampleSrc:"[AR] A: Come up!\nB: I am coming! Which floor?\nA: Third.\nB: Is there no elevator?",funFact:"[AR] Short for 'herauf' (up here). Informal register. 'Raufgehen' = go up, 'raufklettern' = climb up. The colloquial prefix rauf- is very common in spoken German."},
        {type:"teach",trg:"rückwärts",src:"[AR] backward",pos:"adv",gender:null,note:"[AR] Rück (back) + -wärts. 'Rückwärts einparken' = reverse parking.",example:"A: Können Sie rückwärts einparken?\nB: Natürlich! Das ist Pflicht bei der Fahrprüfung.\nA: In meinem Land auch.\nB: Rückwärts ist rückwärts, überall gleich!",exampleSrc:"[AR] A: Can you reverse park?\nB: Of course! That is mandatory in the driving test.\nA: In my country too.\nB: Backward is backward, the same everywhere!",funFact:"[AR] Germans must master rückwärts einparken for the driving test. 'Rückwärtsgang' = reverse gear. The -wärts suffix indicates direction."},
        {type:"teach",trg:"voraus",src:"[AR] ahead / in advance",pos:"adv",gender:null,note:"[AR] 'Im Voraus' = in advance. 'Geradeaus' = straight ahead.",example:"A: Bitte im Voraus bezahlen.\nB: Okay, wie viel?\nA: 25 Euro.\nB: Hier, bitte.",exampleSrc:"[AR] A: Please pay in advance.\nB: Okay, how much?\nA: 25 euros.\nB: Here you are.",funFact:"[AR] 'Im Voraus' (in advance) and 'voraus' (ahead) are essential words. 'Voraussetzung' (prerequisite) and 'voraussichtlich' (presumably) build on the same root."},
        {type:"teach",trg:"entlang",src:"[AR] along",pos:"prep",gender:null,note:"[AR] After noun + accusative, or before noun + dative/genitive.",example:"A: Gehen Sie die Straße entlang.\nB: Wie weit?\nA: Bis zum Hafen.\nB: Am Ufer entlang?",exampleSrc:"[AR] A: Walk along the street.\nB: How far?\nA: To the harbor.\nB: Along the shore?",funFact:"[AR] Unusual grammar: 'die Straße entlang' (after noun, accusative) or 'entlang der Straße' (before noun, genitive). Both are correct."},
        {type:"match",pairs:[
            {trg:"pauschal",src:"all-inclusive"},
            {trg:"aufwärts",src:"upward"},
            {trg:"abwärts",src:"downward"},
            {trg:"quer",src:"across/diagonal"}
          ]},
        {type:"mc",q:"'Gehen Sie die Straße entlang bis zum Hafen.' Was bedeutet 'entlang'?",opts:["gegen","weg von","an der Straße weiter","vor der Straße"],ans:"an der Straße weiter",hint:"[AR] This preposition describes following a path or road in one direction."}
      ]},
    {id:"deu_r15l10",title:"Verben und Varianten",icon:"🔄",xp:10,board:true,steps:[
        {type:"intro",title:"Verben und Varianten",desc:"[AR] Remove, flow, park, cross, turn around, exchange: seven action verbs plus German, Austrian, and Swiss vocabulary variants. The DACH region speaks one language in many dialects.",goals:[
            "[AR] Learn seven action verbs for movement and change",
            "[AR] Discover DACH vocabulary variants",
            "[AR] Practice all grammar patterns from this unit"
          ]},
        {type:"teach",trg:"entfernen",src:"[AR] to remove / to be distant",pos:"verb",gender:null,note:"[AR] Ent- (away) + fernen (from fern = far). Inseparable.",example:"A: Bitte entfernen Sie den Gegenstand.\nB: Welchen Gegenstand?\nA: Den Koffer dort.\nB: Oh, das ist meiner! Entschuldigung.",exampleSrc:"[AR] A: Please remove the object.\nB: Which object?\nA: The suitcase there.\nB: Oh, that is mine! Sorry.",funFact:"[AR] Also used as adjective: 'weit entfernt' (far away), 'drei Kilometer entfernt' (three kilometers away). Inseparable prefix ent- means 'away from.'"},
        {type:"teach",trg:"fließen",src:"[AR] to flow",pos:"verb",gender:null,note:"[AR] Irregular: fließt, floss, ist geflossen. Related to English 'flow.'",example:"A: Die Elbe fließt durch Hamburg.\nB: Wohin fließt sie?\nA: In die Nordsee.\nB: Der Fluss ist riesig hier.",exampleSrc:"[AR] A: The Elbe flows through Hamburg.\nB: Where does it flow?\nA: Into the North Sea.\nB: The river is enormous here.",funFact:"[AR] Hamburg exists because the Elbe fließt to the North Sea. Irregular conjugation: fließt, floss, ist geflossen. Related to English 'flow' and 'flood.'"},
        {type:"teach",trg:"parkieren",src:"[AR] to park (Swiss)",pos:"verb",gender:null,note:"[AR] Swiss German for 'parken.' The -ieren ending follows French/Latin loan patterns.",example:"A: Wo kann man hier parkieren?\nB: In der Schweiz sagt man parkieren.\nA: Und in Deutschland?\nB: Parken! Ohne -ieren.",exampleSrc:"[AR] A: Where can you park here?\nB: In Switzerland they say parkieren.\nA: And in Germany?\nB: Parken! Without -ieren.",funFact:"[AR] In Germany and Austria: 'parken.' In Switzerland: 'parkieren.' The -ieren ending follows the French/Latin loan pattern common in Swiss German."},
        {type:"teach",trg:"überqueren",src:"[AR] to cross",pos:"verb",gender:null,note:"[AR] Über (over) + queren (to cross). Inseparable. More formal than 'gehen über.'",example:"A: Bitte überqueren Sie die Straße am Zebrastreifen.\nB: Natürlich!\nA: In Deutschland wartet man bei Rot.\nB: Ja, das habe ich gelernt!",exampleSrc:"[AR] A: Please cross the street at the crosswalk.\nB: Of course!\nA: In Germany you wait at red.\nB: Yes, I learned that!",funFact:"[AR] Inseparable: 'Er überquert die Straße.' More formal than 'über die Straße gehen.' Past participle: 'überquert' (no ge-)."},
        {type:"teach",trg:"umdrehen",src:"[AR] to turn around",pos:"verb",gender:null,note:"[AR] Um (around) + drehen (to turn). Separable. Also reflexive: 'sich umdrehen.'",example:"A: Dreh dich um!\nB: Warum?\nA: Sieh mal, der Sonnenuntergang!\nB: Oh, wunderschön!",exampleSrc:"[AR] A: Turn around!\nB: Why?\nA: Look, the sunset!\nB: Oh, beautiful!",funFact:"[AR] Separable: 'Dreh dich um!' (Turn around!). Reflexive: 'sich umdrehen.' Verumius dreht sich um und sieht Lukas auf dem Bahnsteig."},
        {type:"teach",trg:"umtauschen",src:"[AR] to exchange (goods/money)",pos:"verb",gender:null,note:"[AR] Um (exchange) + tauschen (to swap). Separable.",example:"A: Kann ich das umtauschen?\nB: Nur mit Kassenbon.\nA: Hier ist er.\nB: Gut. Was möchten Sie stattdessen?",exampleSrc:"[AR] A: Can I exchange this?\nB: Only with the receipt.\nA: Here it is.\nB: Good. What would you like instead?",funFact:"[AR] 'Euro in Dollar umtauschen' = to exchange euros for dollars. 'Umtausch nur innerhalb von 14 Tagen' = exchange only within 14 days. Standard German retail policy."},
        {type:"teach",trg:"das Zeug",src:"[AR] the stuff / things",pos:"noun",gender:"n",note:"[AR] Very versatile. 'Zeug' appears in many compounds: Fahrzeug, Werkzeug, Spielzeug.",example:"A: Was ist das für ein Zeug?\nB: Mein Reisezeug.\nA: Du hast viel Zeug dabei!\nB: Ja, ich packe immer zu viel ein.",exampleSrc:"[AR] A: What kind of stuff is that?\nB: My travel stuff.\nA: You have a lot of stuff with you!\nB: Yes, I always pack too much.",funFact:"[AR] 'Zeug' is one of German's most productive compound elements: Fahrzeug (vehicle), Flugzeug (airplane), Werkzeug (tool), Spielzeug (toy), Feuerzeug (lighter). Literally 'stuff for X.'"},
        {type:"tip",title:"Germany, Austria, Switzerland: one language, many words",text:"[AR] German is spoken in Germany (D), Austria (A), and Switzerland (CH). But each country has its own vocabulary, sometimes for everyday items.\n\nCream: Sahne (D) / Rahm (CH) / Obers (A)\nWhipped cream: Schlagsahne (D) / Schlagrahm (CH) / Schlagobers (A)\nCarrot: Karotte (D-south) / Möhre (D-north) / Rübe (D-regional)\nBread roll: Brötchen (D-north) / Semmel (D-south, A) / Weggli (CH)\nJam: Marmelade (D, A) / Konfitüre (CH, formal D)\nSidewalk: Bürgersteig (D-north) / Gehsteig (D-south, A) / Trottoir (CH)\nBicycle: Fahrrad (D, A) / Velo (CH)\nParking: parken (D, A) / parkieren (CH)\n\nHamburg's 'Moin!' vs Berlin's 'Hallo' vs Bavaria's 'Grüß Gott' vs Switzerland's 'Grüezi' shows that even greetings split by region.",deepDive:{title:"Why so many variants?",text:"[AR] Germany was not unified until 1871. Before that, it was hundreds of independent states, each developing its own dialect and vocabulary. Austria and Switzerland went their own way even earlier.\n\nSwiss German (Schweizerdeutsch) is so different from Standard German that Germans often cannot understand it. Austrian German (Osterreichisches Deutsch) is closer but has many unique words, especially for food.\n\nThe Goethe B1 exam accepts all standard variants. 'Semmel' is as correct as 'Brötchen.' Understanding regional variants is part of B1 competence."}},
        {type:"teach",trg:"der Rahm",src:"[AR] cream (Swiss German)",pos:"noun",gender:"m",note:"[AR] Standard in Switzerland. 'Rahmkäse' = cream cheese in Swiss German.",example:"A: In der Schweiz sagt man Rahm.\nB: Statt Sahne?\nA: Genau. Rahm, nicht Sahne.\nB: Interessant! Gleiches Produkt.",exampleSrc:"[AR] A: In Switzerland they say Rahm.\nB: Instead of Sahne?\nA: Exactly. Rahm, not Sahne.\nB: Interesting! Same product.",funFact:"[AR] Standard in Switzerland. 'Rahmkäse' = cream cheese in Swiss German. In Germany: Sahne. Same product, different countries."},
        {type:"teach",trg:"der Schlagrahm",src:"[AR] whipped cream (Swiss)",pos:"noun",gender:"m",note:"[AR] Schlag + Rahm. On Swiss cafe menus where Germans see Schlagsahne.",example:"A: Einen Kaffee mit Schlagrahm, bitte.\nB: Sie sind aus der Schweiz?\nA: Ja! In Zürich sagen wir Schlagrahm.\nB: Hier heißt das Schlagsahne.",exampleSrc:"[AR] A: A coffee with whipped cream, please.\nB: You are from Switzerland?\nA: Yes! In Zürich we say Schlagrahm.\nB: Here it is called Schlagsahne.",funFact:"[AR] On a Swiss cafe menu where a German menu says Schlagsahne, you find Schlagrahm. Same product, different tradition."},
        {type:"teach",trg:"die Möhre",src:"[AR] carrot (northern German)",pos:"noun",gender:"f",note:"[AR] In Hamburg, you hear Möhre. In Munich: Karotte.",example:"A: Möhren oder Karotten?\nB: In Hamburg: Möhren!\nA: Schmecken sie anders?\nB: Nein, nur der Name ist anders.",exampleSrc:"[AR] A: Möhren or Karotten?\nB: In Hamburg: Möhren!\nA: Do they taste different?\nB: No, only the name is different.",funFact:"[AR] Verumius learned Karotte first, now hears Möhre in Hamburg. In some regions: 'Gelbe Rübe.' Three words for one vegetable."},
        {type:"teach",trg:"die Konfitüre",src:"[AR] jam/preserve (Swiss/formal)",pos:"noun",gender:"f",note:"[AR] EU regulation says non-citrus jam must be called Konfitüre. Swiss standard.",example:"A: Das ist Konfitüre, nicht Marmelade.\nB: Was ist der Unterschied?\nA: Technisch nur Zitrus = Marmelade.\nB: Das wusste ich nicht!",exampleSrc:"[AR] A: That is Konfitüre, not Marmelade.\nB: What is the difference?\nA: Technically only citrus = Marmelade.\nB: I did not know that!",funFact:"[AR] EU regulation says only citrus preserves can be 'Marmelade.' Everything else is technically 'Konfitüre.' The Swiss just followed the rule from the start."},
        {type:"teach",trg:"das Schlagobers",src:"[AR] whipped cream (Austrian)",pos:"noun",gender:"n",note:"[AR] Schlag + Obers (cream, Austrian). In a Viennese Kaffeehaus: essential.",example:"A: Einen Melange mit Schlagobers, bitte!\nB: Das klingt wienerisch!\nA: Ja, in Wien sagt man Schlagobers.\nB: Und in Berlin: Schlagsahne.",exampleSrc:"[AR] A: A Melange with whipped cream, please!\nB: That sounds Viennese!\nA: Yes, in Vienna they say Schlagobers.\nB: And in Berlin: Schlagsahne.",funFact:"[AR] In a Viennese Kaffeehaus: 'Einen Melange mit Schlagobers, bitte!' In Berlin, that same order is 'Milchkaffee mit Schlagsahne.' Language geography in action."},
        {type:"mc",q:"Während ___ langen Reise schlief Verumius sofort ein.",opts:["die","der","des","dem"],ans:"der",hint:"[AR] Während takes genitive. Reise is feminine. What does 'die' become in genitive?"},
        {type:"fb",s:"Verumius traf den {1} am Bahnsteig.",a:["Kollegen"],opts:["Kollegen","Kollege","Kolleges","Kolleg"],hint:"[AR] Kollege is N-Deklination. What ending does it take in accusative?",sSrc:"[AR] Verumius met the colleague on the platform."},
        {type:"mc",q:"In a Swiss cafe, how would you order whipped cream?",opts:["Schlagsahne","Schlagobers","Schlagrahm","Sahne"],ans:"Schlagrahm",hint:"[AR] Switzerland uses Rahm for cream. Whipped = Schlag + Rahm."},
        {type:"drag_fill",s:"{1} {2} Aufenthalts in Hamburg besuchte Verumius die Elbphilharmonie.",blanks:{"1":"Während","2":"des"},pool:["Während","Trotz","des","der","dem","eines"],hint:"[AR] DURING the stay. Aufenthalt is masculine. Genitive masculine: des.",sSrc:"[AR] During the stay in Hamburg Verumius visited the Elbphilharmonie."},
        {type:"match",pairs:[
            {trg:"Sahne (D)",src:"cream"},
            {trg:"Rahm (CH)",src:"cream"},
            {trg:"Semmel (A/South)",src:"bread roll"},
            {trg:"Möhre (North)",src:"carrot"},
            {trg:"Trottoir (CH)",src:"sidewalk"}
          ]}
      ]}
  ]};

export default UNIT_15_AR;
